// Twilio address / surcharge helpers (module-scope for use in both loadData & bot.on)
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
function needsTwilioAddress(countryCode, provider) {
  if (provider !== 'twilio') return false
  const cc = twilioService.NO_COMPLIANCE_COUNTRIES.find(c => c.code === countryCode)
  return cc?.addrReq?.includes('any') || cc?.addrReq?.includes('local') || false
}

function getAddressLocationText(countryCode) {
  const cc = twilioService.NO_COMPLIANCE_COUNTRIES.find(c => c.code === countryCode)
  if (cc?.addrReq?.includes('local')) return { type: 'local', text: `must be located in <b>${cc.name.replace(/^.{1,4}\s/, '')}</b>` }
  if (cc?.addrReq?.includes('any')) return { type: 'any', text: 'can be from <b>any country</b> worldwide' }
  return null
}

/**
 * Determine if a payment coin should be refunded as USD.
 * Crypto payments (crypto_dynopay_ETH, crypto_blockbee_BTC, etc.) are always USD-equivalent.
 * Wallet USD payments use the u.usd label or 'wallet_usd'.
 * Everything else that isn't explicitly NGN → treat as USD.
 */
function isUsdRefundCoin(coin, u) {
  if (!coin) return true // default to USD
  if (coin === u?.usd || coin === 'USD') return true
  if (coin.startsWith('wallet_usd') || coin.startsWith('wallet_USD')) return true
  if (coin.startsWith('crypto')) return true // all crypto → USD
  if (coin === u?.ngn || coin === 'NGN') return false
  if (coin.startsWith('wallet_ngn') || coin.startsWith('wallet_NGN')) return false
  if (coin.startsWith('bank_ngn')) return false
  return true // default to USD for unknown coins
}

// Get number monthly cost surcharge (>= $5 = surcharge, < $5 = free with plan)
function getNumberSurcharge(countryCode, numberType) {
  const cc = twilioService.NO_COMPLIANCE_COUNTRIES.find(c => c.code === countryCode)
  const monthlyPrice = cc?.prices?.[numberType] || 0
  return monthlyPrice >= twilioService.NUMBER_COST_FREE_THRESHOLD ? monthlyPrice : 0
}

// Get sub-number price: max($25, twilioMonthlyCost * 1.5)
function getSubNumberPrice(countryCode, numberType, provider) {
  if (provider !== 'twilio') {
    return phoneConfig.SUB_NUMBER_BASE_PRICE // Telnyx numbers: flat $25
  }
  const cc = twilioService.NO_COMPLIANCE_COUNTRIES.find(c => c.code === countryCode)
  const monthlyPrice = cc?.prices?.[numberType] || 0
  const withMarkup = monthlyPrice * (1 + phoneConfig.SUB_NUMBER_MARKUP) // cost + 50% markup
  return Math.max(phoneConfig.SUB_NUMBER_BASE_PRICE, Math.round(withMarkup * 100) / 100)
}

// ── Get pool-wide minutes used for a number (parent + all sub-numbers sharing the plan) ──
function getPoolMinutesUsed(numbers, num) {
  if (num.isSubNumber && num.parentNumber) {
    // This is a sub-number: find parent + all siblings
    const parent = numbers.find(n => n.phoneNumber === num.parentNumber && !n.isSubNumber)
    const siblings = numbers.filter(n => n.isSubNumber && n.parentNumber === num.parentNumber)
    return (parent?.minutesUsed || 0) + siblings.reduce((sum, n) => sum + (n.minutesUsed || 0), 0)
  }
  // This is a parent: own + all sub-numbers under it
  const subs = numbers.filter(n => n.isSubNumber && n.parentNumber === num.phoneNumber)
  return (num.minutesUsed || 0) + subs.reduce((sum, n) => sum + (n.minutesUsed || 0), 0)
}

// ── Get the plan limit for a number (sub-numbers use parent's plan) ──
function getPoolMinuteLimit(numbers, num) {
  if (num.isSubNumber && num.parentNumber) {
    const parent = numbers.find(n => n.phoneNumber === num.parentNumber && !n.isSubNumber)
    return phoneConfig.plans[parent?.plan || num.plan]?.minutes || Infinity
  }
  return phoneConfig.plans[num.plan]?.minutes || Infinity
}

// ── Get pool-wide SMS used (parent + sub-numbers) ──
function getPoolSmsUsed(numbers, num) {
  if (num.isSubNumber && num.parentNumber) {
    const parent = numbers.find(n => n.phoneNumber === num.parentNumber && !n.isSubNumber)
    const siblings = numbers.filter(n => n.isSubNumber && n.parentNumber === num.parentNumber)
    return (parent?.smsUsed || 0) + siblings.reduce((sum, n) => sum + (n.smsUsed || 0), 0)
  }
  const subs = numbers.filter(n => n.isSubNumber && n.parentNumber === num.phoneNumber)
  return (num.smsUsed || 0) + subs.reduce((sum, n) => sum + (n.smsUsed || 0), 0)
}

function getPoolSmsLimit(numbers, num) {
  if (num.isSubNumber && num.parentNumber) {
    const parent = numbers.find(n => n.phoneNumber === num.parentNumber && !n.isSubNumber)
    return phoneConfig.plans[parent?.plan || num.plan]?.sms || Infinity
  }
  return phoneConfig.plans[num.plan]?.sms || Infinity
}

/**
 * Compute the max time limit (in seconds) a call should be allowed to run,
 * based on the user's remaining plan minutes + wallet overage balance.
 * Used to set Twilio `timeLimit` on <Dial> for real-time billing enforcement.
 *
 * @param {'inbound'|'outbound'|'forwarding'} mode
 *   - inbound: plan minutes first, then wallet overage
 *   - outbound/forwarding: wallet only (at the given rate)
 * @param {object} opts
 *   - planMinutesRemaining {number} (only for inbound)
 *   - walletBalance {number} USD
 *   - ratePerMinute {number} USD (overage rate or forwarding rate)
 * @returns {number} seconds (capped between 60 and 14400)
 */
function computeDialTimeLimit(mode, { planMinutesRemaining = 0, walletBalance = 0, ratePerMinute = 0.04 }) {
  let totalSeconds = 0
  if (mode === 'inbound') {
    // Plan minutes first, then wallet overage
    totalSeconds = planMinutesRemaining * 60
    if (ratePerMinute > 0 && walletBalance > 0) {
      totalSeconds += Math.floor(walletBalance / ratePerMinute) * 60
    }
  } else {
    // Outbound / forwarding — wallet only
    if (ratePerMinute > 0 && walletBalance > 0) {
      totalSeconds = Math.floor(walletBalance / ratePerMinute) * 60
    }
  }
  // Clamp: min 60s (1 min), max 14400s (4 hours — Twilio max)
  return Math.max(60, Math.min(14400, totalSeconds))
}

