    'select-dns-record-id-to-update': async () => {
      const records = info?.dnsRecords || []
      const hasNS = records.some(r => r.recordType === 'NS')
      let nonNsIndex = 0
      const recordBtns = []
      // Add consolidated "Update Nameservers" button if NS records exist
      if (hasNS) {
        const nsRecords = records.filter(r => r.recordType === 'NS')
        const nsPreview = nsRecords.map((r, i) => `NS${i + 1}: ${(r.recordContent || '—').length > 25 ? r.recordContent.substring(0, 23) + '..' : r.recordContent}`).join(', ')
        recordBtns.push([`🔄 Update Nameservers (${nsPreview})`])
      }
      // Add non-NS records
      records.forEach((r, i) => {
        if (r.recordType === 'NS') return
        nonNsIndex++
        const label = r.recordContent || '—'
        const short = label.length > 30 ? label.substring(0, 28) + '..' : label
        recordBtns.push([`${nonNsIndex}. ${r.recordType} → ${short}`])
      })
      const keyboard = { parse_mode: 'HTML', reply_markup: { keyboard: [...recordBtns, [t.back, t.cancel]] } }
      send(chatId, t.updateDnsTxt, keyboard)
      await set(state, chatId, 'action', 'select-dns-record-id-to-update')
    },
    'type-dns-record-data-to-update': async (id, recordType, currentValue) => {
      set(state, chatId, 'dnsRecordIdToUpdate', id)
      await set(state, chatId, 'action', 'type-dns-record-data-to-update')

      // For NS records, show full arrangement context
      if (recordType === 'NS') {
        const records = info?.dnsRecords || []
        const nsRecords = records.filter(r => r.recordType === 'NS')
        const nsIndex = nsRecords.findIndex((r, i) => records.indexOf(r) === id || i === records.slice(0, id + 1).filter(x => x.recordType === 'NS').length - 1)
        const slotNum = nsIndex >= 0 ? nsIndex + 1 : 1
        if (t.updateNsPrompt) {
          send(chatId, t.updateNsPrompt(nsRecords, slotNum), bc)
        } else {
          send(chatId, ({ en: `<b>Update Nameserver NS${slotNum}</b>
Current: <b>${currentValue || 'N/A'}</b>

Enter new nameserver:`, fr: `<b>Mettre à jour NS${slotNum}</b>
Actuel : <b>${currentValue || 'N/A'}</b>

Entrez le nouveau serveur de noms :`, zh: `<b>更新域名服务器 NS${slotNum}</b>
当前：<b>${currentValue || 'N/A'}</b>

输入新的域名服务器：`, hi: `<b>नेमसर्वर NS${slotNum} अपडेट करें</b>
वर्तमान: <b>${currentValue || 'N/A'}</b>

नया नेमसर्वर दर्ज करें:` }[lang] || `<b>Update Nameserver NS${slotNum}</b>
Current: <b>${currentValue || 'N/A'}</b>

Enter new nameserver:`), bc)
        }
        return
      }

      const prompt = t.askUpdateDnsContent[recordType]
      if (typeof prompt === 'function') {
        send(chatId, prompt(currentValue), bc)
      } else if (prompt) {
        send(chatId, prompt, bc)
      } else {
        send(chatId, ({ en: `<b>Update ${recordType} Record</b>

Enter new value:`, fr: `<b>Mettre à jour l'enregistrement ${recordType}</b>

Entrez la nouvelle valeur :`, zh: `<b>更新 ${recordType} 记录</b>

输入新值：`, hi: `<b>${recordType} रिकॉर्ड अपडेट करें</b>

नई वैल्यू दर्ज करें:` }[lang] || `<b>Update ${recordType} Record</b>

Enter new value:`), bc)
      }
    },

