          const { address: bbAddr, bb } = await getCryptoDepositAddress(ticker, chatId, SELF_URL, `/crypto-wallet?a=b&ref=${ref}&`)
          if (!bbAddr) return send(chatId, t.errorFetchingCryptoAddress, trans('o'))
