async function buyDomain(chatId, domain, registrar, nsChoice, customNS) {
  // ref https://www.mongodb.com/docs/manual/core/dot-dollar-considerations
  const domainSanitizedForDb = domain.replaceAll('.', '@')

  // Use unified domain service for registration
  registrar = registrar || 'ConnectReseller'
  nsChoice = nsChoice || 'provider_default'

  const result = await domainService.registerDomain(domain, registrar, nsChoice, db, chatId, customNS)
  if (result.success) {
    set(domainsOf, chatId, domainSanitizedForDb, true)
  }

  return result
}

const formatLinks = links => {
  return links.map(d => `${d.clicks} ${d.clicks === 1 ? 'click' : 'clicks'} → ${d.shorter} → ${d.url}`)
}

const buyDomainFullProcess = async (chatId, lang, domain) => {
  try {
    sendMessage(chatId, translation('t.paymentSuccessFul', lang), rem)
    let info = await get(state, chatId)
    let registrar = info?.registrar || 'ConnectReseller'
    const nsChoice = info?.nsChoice || 'provider_default'
    const customNS = info?.customNS || null
    const buyResult = await buyDomain(chatId, domain, registrar, nsChoice, customNS)
    if (buyResult.error) {
      // Send detailed error to admin/dev only — user gets generic message
      const adminMsg = `❌ Domain purchase failed: ${domain} | user: ${chatId} | error: ${buyResult.error}`
      log(adminMsg)
      sendMessage(TELEGRAM_DEV_CHAT_ID, adminMsg)
      // User-facing message — no provider names, no raw errors
      const userMsg = translation('t.domainPurchasedFailed', lang, domain)
      sendMessage(chatId, userMsg)
      return userMsg
    }
    // Track actual registrar — may differ from original if CR→OP fallback occurred
    registrar = buyResult.registrar || registrar

    // Save registration outcome to state for pricing in payment handler
    if (buyResult.registrarChanged) {
      // Fallback occurred (e.g., CR→OP) — no savings, charge shown price
      log(`[buyDomainFullProcess] Registrar fallback for ${domain}: registered via ${buyResult.registrar} (actual price: $${buyResult.actualPrice || 'unknown'})`)
      await set(state, chatId, 'registrarFallback', true)
      if (buyResult.actualPrice) {
        await set(state, chatId, 'actualPrice', buyResult.actualPrice)
      }
      await set(state, chatId, 'actualRegistrar', buyResult.registrar)
    } else {
      // Cheaper registrar succeeded — savings may apply
      log(`[buyDomainFullProcess] ${domain} registered via primary registrar ${buyResult.registrar} — potential savings`)
      await set(state, chatId, 'registrarFallback', false)
      await set(state, chatId, 'actualRegistrar', buyResult.registrar)
    }

    send(chatId, translation('t.domainBoughtSuccess', lang, domain), translation('o', lang))

    // NS was set at registration time (passed to registrar API directly) — no post-reg update needed
    if (nsChoice !== 'provider_default' && buyResult.nameservers && buyResult.nameservers.length >= 2) {
      const nsLabel = nsChoice === 'cloudflare' ? 'Cloudflare' : 'Custom'
      log(`[buyDomainFullProcess] ${domain} registered with ${nsLabel} NS: ${buyResult.nameservers.join(', ')} (registrar: ${registrar})`)
    }

    if (info?.askDomainToUseWithShortener === false) return

    // ── Persist shortener activation intent ──
    await createActivationTask(chatId, domain, lang)

    // Link domain to Railway/Render for URL shortener
    const { server, error, recordType, txtHost, txtValue } =
      process.env.HOSTED_ON === 'render'
        ? await saveDomainInServerRender(domain)
        : await saveDomainInServerRailway(domain)

    if (error) {
      const m = translation('t.errorSavingDomain', lang)
      sendMessage(chatId, m)
      await markFailed(domain, error).catch(() => {})
      return m
    }

    // ── Persist Railway link complete ──
    await markRailwayLinked(domain, server, recordType)

    sendMessage(chatId, translation('t.domainLinking', lang, domain))

    // Add shortener DNS via unified service — auto-resolves A/CNAME conflicts,
    // routes to Cloudflare when domain metadata has nameserverType='cloudflare' + cfZoneId.
    await sleep(5000) // Brief delay for DB metadata propagation
    const addResult = await domainService.addShortenerCNAME(domain, server, db, txtHost, txtValue)
    if (addResult.error || !addResult.success) {
      log(`[buyDomainFullProcess] DNS record add failed via domainService for ${domain}: ${addResult.error || 'unknown'}`)
      // Fallback: try direct CR DNS add for ConnectReseller domains
      if (registrar === 'ConnectReseller') {
        log(`[buyDomainFullProcess] Falling back to direct CR DNS add for ${domain}`)
        await sleep(60000) // CR needs propagation time
        const { error: saveServerInDomainError } = await saveServerInDomain(domain, server, recordType)
        if (saveServerInDomainError) {
          const m = `Error saving DNS record for domain: ${saveServerInDomainError}`
          sendMessage(chatId, m)
          await markFailed(domain, saveServerInDomainError).catch(() => {})
          return m
        }
      } else {
        const m = `Error saving DNS record for domain: ${addResult.error || 'Unknown error'}`
        sendMessage(chatId, m)
        await markFailed(domain, addResult.error || 'Unknown error').catch(() => {})
        return m
      }
    }

    // ── Persist DNS complete ──
    await markDnsAdded(domain)

    sendMessage(chatId, translation('t.domainBought', lang).replaceAll('{{domain}}', domain))
    regularCheckDns(bot, chatId, domain, lang)

    // ── Persist fully completed ──
    await markCompleted(domain)

    return false // error = false
  } catch (error) {
    const errorMessage = `err buyDomainFullProcess ${error?.message} ${safeStringify(error?.response?.data)}`
    sendMessage(TELEGRAM_DEV_CHAT_ID, errorMessage)
    console.error(errorMessage)
    return errorMessage
  }
}

schedule.scheduleJob('*/5 * * * *', function() {
  checkVPSPlansExpiryandPayment()
})

async function checkVPSPlansExpiryandPayment() {
  // Guard: Ensure database is initialized before proceeding
  if (!vpsPlansOf || typeof vpsPlansOf.find !== 'function') {
    console.log('[VPS Scheduler] Database not ready yet, skipping check')
    return
  }

  const now = new Date()
  const oneDayFromNow = new Date(now.getTime() + 1 * 24 * 60 * 60 * 1000)
  const threeDaysFromNow = new Date(now.getTime() + 3 * 24 * 60 * 60 * 1000)

  try {
    // ═══════════════════════════════════════════════════════════════
    // Phase 1: AUTO-RENEW — 1 day before expiry (end_time within next 24h)
    // Uses smartWalletDeduct (USD → NGN fallback, atomic)
    // ═══════════════════════════════════════════════════════════════
    const dueForRenewal = await vpsPlansOf.find({
      'end_time': { $lte: oneDayFromNow, $gt: now },
      'status': { $in: ['RUNNING', 'running'] },
      '_autoRenewAttempted': { $ne: true }
    }).toArray()

    for (const vpsPlan of dueForRenewal) {
      const { chatId, _id, planPrice, vpsId, label, autoRenewable, contaboInstanceId } = vpsPlan
      const info = await state.findOne({ _id: parseFloat(chatId) })
      const lang = info?.userLanguage || 'en'
      const displayName = label || vpsPlan.name || 'VPS'
      const expiryDate = new Date(vpsPlan.end_time).toLocaleDateString()

      if (!autoRenewable) {
        // Auto-renew disabled — mark as pending cancellation, warn user
        await vpsPlansOf.updateOne({ _id }, { $set: { status: 'PENDING_CANCELLATION', _autoRenewAttempted: true } })
        send(chatId, `⚠️ <b>VPS Expiring — No Auto-Renewal</b>\n\n🖥️ <b>${displayName}</b> expires on <b>${expiryDate}</b>.\nAuto-renewal is <b>OFF</b>.\n\n⏰ <b>Renew manually before the deadline</b> or your server will be permanently deleted.\n\nGo to: VPS/RDP → Manage → Renew Now`)
        log(`[VPS Scheduler] ${displayName} marked PENDING_CANCELLATION for ${chatId} — auto-renew disabled`)
        continue
      }

      // Try to charge wallet: USD first, then NGN
      const deductResult = await smartWalletDeduct(walletOf, chatId, Number(planPrice))

      if (deductResult.success) {
        // Renew: extend by 1 month
        const newEnd = new Date(vpsPlan.end_time)
        newEnd.setMonth(newEnd.getMonth() + 1)

        await vpsPlansOf.updateOne({ _id }, {
          $set: { end_time: newEnd, status: 'RUNNING', _autoRenewAttempted: true, _reminder3DaySent: false, _reminder1DaySent: false }
        })
        const currSymbol = deductResult.currency === 'ngn' ? '₦' : '$'
        const chargedDisplay = deductResult.currency === 'ngn'
          ? `₦${Number(deductResult.chargedNgn).toFixed(2)} (≈ $${planPrice})`
          : `$${planPrice}`
        set(payments, nanoid(), `Wallet,VPSAutoRenew,Monthly,$${planPrice},${chatId},${new Date()},${deductResult.currency}`)

        const { usdBal: usd } = await getBalance(walletOf, chatId)
        send(chatId, `✅ <b>VPS Auto-Renewed</b>\n\n🖥️ <b>${displayName}</b> renewed for 1 month.\n💰 ${chargedDisplay} deducted from ${deductResult.currency.toUpperCase()} wallet.\n📅 New expiry: <b>${newEnd.toLocaleDateString()}</b>\n\n💳 Balance: $${usd.toFixed(2)} / ₦${ngn.toFixed(2)}`)
        log(`[VPS Scheduler] Auto-renewed ${displayName} for ${chatId}, charged ${deductResult.currency} $${planPrice}`)
      } else {
        // Both USD and NGN failed — mark pending cancellation
        await vpsPlansOf.updateOne({ _id }, { $set: { status: 'PENDING_CANCELLATION', _autoRenewAttempted: true } })
        const { usdBal } = deductResult
        send(chatId, `🚨 <b>URGENT — VPS Renewal Failed</b>\n\n🖥️ <b>${displayName}</b> could not be auto-renewed.\n💰 Balance: $${(usdBal || 0).toFixed(2)}\n💵 Required: <b>$${planPrice}/mo</b>\n\n⚠️ <b>Your server will be permanently deleted on ${expiryDate}</b> unless you renew manually.\n\nGo to: VPS/RDP → Manage → 📅 Renew Now`)
        send(TELEGRAM_ADMIN_CHAT_ID, `⚠️ <b>VPS Renewal Failed</b>\nUser: ${chatId}\nVPS: ${displayName}\nPrice: $${planPrice}\nBalance: $${(usdBal || 0).toFixed(2)}`, { parse_mode: 'HTML' })
        log(`[VPS Scheduler] ${displayName} PENDING_CANCELLATION for ${chatId} — balance insufficient ($${usdBal || 0} < $${planPrice})`)
      }
    }

    // ═══════════════════════════════════════════════════════════════
    // Phase 2: DELETE on Contabo — VPS past deadline with failed renewal
    // PENDING_CANCELLATION + end_time <= now → cancel on Contabo + mark CANCELLED
    // ═══════════════════════════════════════════════════════════════
    const pastDeadline = await vpsPlansOf.find({
      'end_time': { $lte: now },
      'status': 'PENDING_CANCELLATION'
    }).toArray()

    for (const vpsPlan of pastDeadline) {
      const { chatId, _id, vpsId, label, contaboInstanceId, planPrice } = vpsPlan
      const displayName = label || vpsPlan.name || 'VPS'
      const info = await state.findOne({ _id: parseFloat(chatId) })
      const lang = info?.userLanguage || 'en'

      try {
        // Delete from Contabo to prevent their billing
        const deleteResult = await deleteVPSinstance(chatId, vpsId)
        if (deleteResult.success) {
          await vpsPlansOf.updateOne({ _id }, { $set: { status: 'CANCELLED', cancelledAt: new Date(), cancelReason: 'auto_renewal_failed' } })
          send(chatId, `❌ <b>VPS Deleted</b>\n\n🖥️ <b>${displayName}</b> has been permanently deleted.\n\n💡 Reason: Auto-renewal failed and no manual renewal was received before the deadline.\n\nYou can purchase a new VPS anytime from the main menu.`)
          send(TELEGRAM_ADMIN_CHAT_ID, `🗑️ <b>VPS Auto-Deleted</b>\nUser: ${chatId}\nVPS: ${displayName}\nReason: Renewal failed, deadline passed\nPrice was: $${planPrice}/mo`, { parse_mode: 'HTML' })
          log(`[VPS Scheduler] DELETED ${displayName} on Contabo for ${chatId} — deadline passed`)
        } else {
          // Delete failed — retry next cycle, alert admin
          log(`[VPS Scheduler] ERROR: Failed to delete ${displayName} on Contabo: ${deleteResult.error}`)
          send(TELEGRAM_ADMIN_CHAT_ID, `🚨 <b>VPS DELETE FAILED</b>\nUser: ${chatId}\nVPS: ${displayName} (vpsId: ${vpsId})\nInstance ID: ${contaboInstanceId}\nError: ${deleteResult.error}\n\n⚠️ Manual deletion required to prevent provider billing!`, { parse_mode: 'HTML' })
        }
      } catch (err) {
        log(`[VPS Scheduler] CRASH deleting ${displayName}: ${err.message}`)
        send(TELEGRAM_ADMIN_CHAT_ID, `🚨 <b>VPS Delete Crash</b>\nUser: ${chatId}\nVPS: ${displayName}\nError: ${err.message}`, { parse_mode: 'HTML' })
      }
    }

    // ═══════════════════════════════════════════════════════════════
    // Phase 3: Also handle any VPS that are RUNNING but past expiry
    // (edge case: old records before this update, or missed scheduler runs)
    // ═══════════════════════════════════════════════════════════════
    const staleExpired = await vpsPlansOf.find({
      'end_time': { $lte: now },
      'status': { $in: ['RUNNING', 'running'] },
      '_autoRenewAttempted': { $ne: true }
    }).toArray()

    for (const vpsPlan of staleExpired) {
      const { chatId, _id, planPrice, vpsId, label, autoRenewable } = vpsPlan
      const displayName = label || vpsPlan.name || 'VPS'
      const info = await state.findOne({ _id: parseFloat(chatId) })
      const lang = info?.userLanguage || 'en'

      // Try one last renewal attempt
      if (autoRenewable) {
        const deductResult = await smartWalletDeduct(walletOf, chatId, Number(planPrice))
        if (deductResult.success) {
          const newEnd = new Date(now)
          newEnd.setMonth(newEnd.getMonth() + 1)
          await vpsPlansOf.updateOne({ _id }, {
            $set: { end_time: newEnd, status: 'RUNNING', _autoRenewAttempted: true, _reminder3DaySent: false, _reminder1DaySent: false }
          })
          const chargedDisplay = deductResult.currency === 'ngn'
            ? `₦${Number(deductResult.chargedNgn).toFixed(2)} (≈ $${planPrice})`
            : `$${planPrice}`
          set(payments, nanoid(), `Wallet,VPSAutoRenew,Monthly,$${planPrice},${chatId},${new Date()},${deductResult.currency}`)
          const { usdBal: usd } = await getBalance(walletOf, chatId)
          send(chatId, `✅ <b>VPS Auto-Renewed</b>\n\n🖥️ <b>${displayName}</b> renewed for 1 month.\n💰 ${chargedDisplay} deducted.\n📅 New expiry: <b>${newEnd.toLocaleDateString()}</b>\n\n💳 Balance: $${usd.toFixed(2)} / ₦${ngn.toFixed(2)}`)
          log(`[VPS Scheduler] Late auto-renewed ${displayName} for ${chatId}`)
          continue
        }
      }
      // Failed or auto-renew off — mark pending cancellation (will be deleted next cycle)
      await vpsPlansOf.updateOne({ _id }, { $set: { status: 'PENDING_CANCELLATION', _autoRenewAttempted: true } })
      const { usdBal } = await getBalance(walletOf, chatId)
      send(chatId, `🚨 <b>URGENT — VPS Expired</b>\n\n🖥️ <b>${displayName}</b> has expired.\n💰 Balance: $${(usdBal).toFixed(2)}\n\n⚠️ <b>Server will be deleted shortly.</b>\nRenew NOW: VPS/RDP → Manage → 📅 Renew Now`)
      log(`[VPS Scheduler] ${displayName} marked PENDING_CANCELLATION (stale) for ${chatId}`)
    }

    // ═══════════════════════════════════════════════════════════════
    // Phase 4: Pre-expiry reminders with wallet balance info
    // ═══════════════════════════════════════════════════════════════
    const soonExpiring = await vpsPlansOf.find({
      'end_time': { $lte: threeDaysFromNow, $gt: oneDayFromNow },
      'status': { $in: ['RUNNING', 'running'] }
    }).toArray()

    for (const vpsPlan of soonExpiring) {
      const { chatId, _id, label, end_time, planPrice } = vpsPlan
      const displayName = label || vpsPlan.name || 'VPS'
      const msLeft = new Date(end_time).getTime() - now.getTime()
      const daysLeft = msLeft / (1000 * 60 * 60 * 24)
      const expiryDate = new Date(end_time).toLocaleDateString()

      // 3-day reminder
      if (daysLeft > 2.5 && daysLeft <= 3.1 && !vpsPlan._reminder3DaySent) {
        const { usdBal } = await getBalance(walletOf, chatId)
        const sufficient = usdBal >= planPrice
        const statusIcon = sufficient ? '✅' : '⚠️'
        send(chatId, `🖥️ <b>VPS Expiring in 3 Days</b>\n\n<b>${displayName}</b> expires on <b>${expiryDate}</b>.\n💵 Required: <b>$${planPrice}/mo</b>\n💳 Balance: $${usdBal.toFixed(2)}\n${statusIcon} ${sufficient ? 'Auto-renewal will be attempted 1 day before expiry.' : 'Insufficient balance — top up or renew manually to keep your server!'}`)
        await vpsPlansOf.updateOne({ _id }, { $set: { _reminder3DaySent: true } })
        log(`[VPS Scheduler] 3-day reminder sent to ${chatId} for ${displayName}`)
      }
    }
  } catch (error) {
    console.error('[VPS Scheduler] Error:', error.message || error)
  }
}

const buyVPSPlanFullProcess = async (chatId, lang, vpsDetails) => {
  try {
    const vmInstance = await createVPSInstance(chatId, vpsDetails)
    if (!vmInstance.success) {
      const m = translation('vp.errorPurchasingVPS', lang, vpsDetails.plan)
      log(m)
      sendMessage(TELEGRAM_DEV_CHAT_ID, m)
      sendMessage(chatId, m)
      return false
    }
    const { data: vpsData } = vmInstance
    let info = await get(state, chatId)

    // NOTE: vm-instance-setup.js already inserts into vpsPlansOf during createVPSInstance.
    // No duplicate insert needed here.

    // For Contabo, SSH keys are attached at creation time (no separate step needed).
    // Just wait for the instance to provision and get an IP.
    send(chatId, translation('vp.vpsProvisioningWait', lang) || '⏳ Your server is being provisioned. Please wait...')
    await sleep(15000)

    // Credentials are returned directly from createVPSInstance for Contabo
    const credentials = vpsData.credentials || { username: vpsData.isRDP ? 'Administrator' : 'root', password: 'Check email' }

    set(state, info._id, 'action', 'none')
    send(chatId, translation('vp.vpsBoughtSuccess', lang, vpsDetails, vpsData, credentials), translation('o', lang))
    try {
      await sendVPSCredentialsEmail(info, vpsData, vpsDetails, credentials)
    } catch (error) {
      log('Error sending email:', error)
      send(TELEGRAM_DEV_CHAT_ID, 'Error sending email', translation('o'))
    }

    // ── Phase 6: Notify admin group about VPS purchase ──
    try {
      const name = await get(nameOf, chatId)
      const isRDP = vpsData.isRDP || vpsDetails.isRDP || false
      const planType = isRDP ? 'RDP' : 'VPS'
      const regionStr = vpsDetails.region ? ` in <b>${vpsDetails.region}</b>` : ''
      notifyGroup(`🖥 <b>New ${planType} Deployed!</b>\nUser ${maskName(name)} just deployed a <b>${vpsDetails.plan || 'Cloud VPS'}</b> server${regionStr}.\nGet yours — /start`)
      if (TELEGRAM_ADMIN_CHAT_ID) send(TELEGRAM_ADMIN_CHAT_ID, `🖥 <b>VPS Purchase</b>\n👤 ${name} (${chatId})\n📦 ${vpsDetails.plan || 'Cloud VPS'}${regionStr}\n💰 $${vpsDetails.totalPrice}\n🖥 IP: ${vpsData.host || 'pending'}`, { parse_mode: 'HTML' })
    } catch (e) {
      log('[VPS] notifyGroup error: ' + e.message)
    }

    return true
  } catch (error) {
    const errorMessage = `err buyVPSPlanFullProcess ${error?.message} ${safeStringify(error?.response?.data)}`
    const m = translation('vp.errorPurchasingVPS', lang, vpsDetails.plan)
    sendMessage(chatId, m)
    sendMessage(TELEGRAM_DEV_CHAT_ID, errorMessage)
    console.error(errorMessage)
    return false
  }
}

const upgradeVPSDetails = async (chatId, lang, vpsDetails) => {
  try {
    log(vpsDetails)
    const vmInstanceDetails = await fetchVPSDetails(chatId, vpsDetails._id)
    if (!vmInstanceDetails) {
      const m = translation('vp.errorUpgradingVPS', lang, vpsDetails.name)
      log(m)
      sendMessage(TELEGRAM_DEV_CHAT_ID, m)
      sendMessage(chatId, m)
      return false
    }
    let vmInstanceUpgrade;
    let message = ''
    switch (vpsDetails.upgradeType) {
      case 'plan':
        vmInstanceUpgrade = await upgradeVPSPlanType(chatId, vpsDetails)
        if (vmInstanceUpgrade.success) {
          await vpsPlansOf.updateOne(
            { vpsId: vpsDetails._id },
            { $set: { 'planPrice': vmInstanceUpgrade.data.price } },
          )
        }
        message = translation('vp.vpsUpgradePlanTypeSuccess', lang, vpsDetails)
        break;
      case 'disk':
        vmInstanceUpgrade = await upgradeVPSDiskType(chatId, vpsDetails)
        if (vmInstanceUpgrade.success) {
          await vpsPlansOf.updateOne(
            { vpsId: vpsDetails._id },
            { $set: { 'planPrice': vmInstanceUpgrade.data.subscription.price } },
          )
        }
        message = translation('vp.vpsUpgradeDiskTypeSuccess', lang, vpsDetails)
        break;
      case 'vps-renew':
        vmInstanceUpgrade = await renewVPSPlan(chatId, vmInstanceDetails.subscription_id)
        if (vmInstanceUpgrade.success) {
          await vpsPlansOf.updateOne(
            { vpsId: vpsDetails._id },
            { $set: { 
              'end_time': new Date(vmInstanceUpgrade.data.subscriptionEnd), 
              'status': 'RUNNING'
            }},
          )
          const expiryDate = date(vmInstanceUpgrade.data.subscriptionEnd)
          message = translation('vp.vpsRenewPlanSuccess', lang, vmInstanceDetails, expiryDate)
        }
        break;
      case 'vps-cPanel-renew':
        // cPanel not available with Contabo
        vmInstanceUpgrade = { success: false, error: 'cPanel not available with current VPS provider' }
        break;
      default:
        break;
    }
    if (!vmInstanceUpgrade?.success) {
      const m = translation('vp.errorPurchasingVPS', lang, vpsDetails.name)
      log(m)
      sendMessage(TELEGRAM_DEV_CHAT_ID, m)
      sendMessage(chatId, m)
      return false
    }

    await set(state, chatId, 'action', 'none')
    send(chatId, message, translation('o', lang))

    // ── Phase 6: Notify admin group about VPS upgrade/renewal ──
    try {
      const name = await get(nameOf, chatId)
      const upgradeLabel = vpsDetails.upgradeType === 'plan' ? 'Plan Upgrade' : vpsDetails.upgradeType === 'disk' ? 'Disk Upgrade' : vpsDetails.upgradeType === 'vps-renew' ? 'Renewal' : 'Update'
      notifyGroup(`⬆️ <b>VPS ${upgradeLabel}!</b>\nUser ${maskName(name)} just ${vpsDetails.upgradeType === 'vps-renew' ? 'renewed' : 'upgraded'} their VPS.\nManage yours — /start`)
      if (TELEGRAM_ADMIN_CHAT_ID) send(TELEGRAM_ADMIN_CHAT_ID, `⬆️ <b>VPS ${upgradeLabel}</b>\n👤 ${name} (${chatId})\n📦 ${vpsDetails.name || 'VPS'}\n💰 $${vpsDetails.totalPrice}`, { parse_mode: 'HTML' })
    } catch (e) {
      log('[VPS] upgrade notifyGroup error: ' + e.message)
    }

    return true
  } catch (error) {
    const errorMessage = `err buyUPgradingVPSProcess ${error?.message} ${safeStringify(error?.response?.data)}`
    const m = translation('vp.errorPurchasingVPS', lang, vpsDetails.name)
    sendMessage(chatId, m)
    sendMessage(TELEGRAM_DEV_CHAT_ID, errorMessage)
    console.error(errorMessage)
    return false
  }
}

