// Shared function to apply a phone plan upgrade — used by wallet, crypto, and bank payment paths
async function applyPhonePlanUpgrade(chatId, num, newPlan, newPrice, lang, paymentMethod) {
  await updatePhoneNumberField(phoneNumbersOf, chatId, num.phoneNumber, 'plan', newPlan)
  await updatePhoneNumberField(phoneNumbersOf, chatId, num.phoneNumber, 'planPrice', newPrice)
  num.plan = newPlan
  num.planPrice = newPrice

  // Re-enable SIP if upgrading to a plan that supports it
  if (phoneConfig.canAccessFeature(newPlan, 'sipCredentials') && num.sipDisabled) {
    await updatePhoneNumberField(phoneNumbersOf, chatId, num.phoneNumber, 'sipDisabled', false)
    num.sipDisabled = false
  }

  const info = await state.findOne({ _id: parseFloat(chatId) })
  await set(state, chatId, 'cpActiveNumber', num)
  await set(state, chatId, 'cpPendingPlan', null)
  await set(state, chatId, 'cpUpgradeData', null)

  const m = phoneConfig.getMsg(lang)
  const confirmMsg = `✅ <b>Plan Upgraded!</b>\n\n📦 New plan: <b>${newPlan.charAt(0).toUpperCase() + newPlan.slice(1)}</b> ($${newPrice}/mo)\n💳 Paid via: ${paymentMethod}\n\nYour new features are now active!`
  sendMessage(chatId, confirmMsg, { parse_mode: 'HTML' })
  const name = await get(nameOf, chatId)
  notifyGroup(`⬆️ <b>Plan Upgrade!</b>\nUser ${maskName(name)} upgraded to <b>${newPlan.charAt(0).toUpperCase() + newPlan.slice(1)}</b> — /start`)

  await set(state, chatId, 'action', 'none')
  log(`[CloudPhone] Plan upgraded for ${chatId}: ${num.phoneNumber} → ${newPlan} ($${newPrice}) via ${paymentMethod}`)
}

async function updatePhoneNumberFeature(col, chatId, phoneNumber, featureKey, value) {
  const userData = await get(col, chatId)
  if (!userData?.numbers) return
  const nums = userData.numbers
  const idx = nums.findIndex(n => n.phoneNumber === phoneNumber)
  if (idx === -1) return
  nums[idx].features = nums[idx].features || {}
  nums[idx].features[featureKey] = value
  // Atomic update: only touch val.numbers, never clobber sibling fields like twilioSubAccountSid/Token
  await setFields(col, chatId, { 'val.numbers': nums })
}

async function updatePhoneNumberField(col, chatId, phoneNumber, fieldKey, value) {
  const userData = await get(col, chatId)
  if (!userData?.numbers) return
  const nums = userData.numbers
  const idx = nums.findIndex(n => n.phoneNumber === phoneNumber)
  if (idx === -1) return
  nums[idx][fieldKey] = value
  // Atomic update: only touch val.numbers, never clobber sibling fields like twilioSubAccountSid/Token
  await setFields(col, chatId, { 'val.numbers': nums })
}

const auth = async (req, res, next) => {
  log(req.hostname + req.originalUrl)
  // Fincra webhooks: merchantReference = our nanoid ref; reference = Fincra's own fcr-p-xxx
  // Crypto callbacks: ref is in query string
  const ref = req?.query?.ref || req?.body?.data?.merchantReference || req?.body?.data?.reference
  log('[auth] Resolved ref:', ref, '| merchantRef:', req?.body?.data?.merchantReference, '| fincraRef:', req?.body?.data?.reference, '| queryRef:', req?.query?.ref)
  const pay = await get(chatIdOfPayment, ref)
  if (!pay) {
    log(`[auth] ⚠️ Payment session NOT FOUND for ref: ${ref}`)
    return res.send(html(translation('t.payError', 'en')))
  }
  req.pay = { ...pay, ref }
  next()
}

// Track processed DynoPay payment IDs to prevent duplicate processing
const processedDynopayPayments = new Set()

// Track processed Fincra webhook refs to prevent duplicate processing
const processedFincraRefs = new Set()

// Map payment_id → refId from pending events, so confirmed/failed events (which lack meta_data) can find the session
const dynopayPaymentIdToRef = new Map()

const authDyno = async (req, res, next) => {
  log('=== DYNOPAY WEBHOOK RECEIVED ===')
  log('URL:', req.hostname + req.originalUrl)
  // Security: Only log non-sensitive fields from webhook payload
  const safeFields = { event: req.body?.event, status: req.body?.status, payment_id: req.body?.payment_id, currency: req.body?.currency }
  log('Webhook summary:', JSON.stringify(safeFields))
  
  const paymentId = req.body?.payment_id
  const event = req.body?.event || req.body?.status

  // ── PENDING events: Extract and store payment_id → refId mapping, then skip ──
  // DynoPay only sends meta_data.refId on pending events; confirmed/failed events lack it.
  // We store the mapping here so later confirmed events can look up the correct session.
  if (event === 'payment.pending' || req.body?.status === 'pending') {
    const pendingRef = req.body?.meta_data?.refId
    if (paymentId && pendingRef) {
      dynopayPaymentIdToRef.set(paymentId, pendingRef)
      log(`[DynoPay] Stored payment_id → refId mapping: ${paymentId} → ${pendingRef}`)
      // Auto-cleanup after 24 hours (some confirmed events arrive very late)
      setTimeout(() => dynopayPaymentIdToRef.delete(paymentId), 86400000)
    }
    log('Skipping pending payment event (stored mapping for future confirmed event)')
    return res.send(html('OK'))
  }

  // ── Skip failed events — only process confirmed payments ──
  if (event === 'payment.failed') {
    log(`[DynoPay] Skipping failed payment event (payment_id: ${paymentId})`)
    return res.send(html('OK'))
  }

  // ── UNDERPAID events: Store mapping + skip — wait for confirmed/settled with full amount ──
  // Processing underpaid events causes handlers to receive partial amounts, which often
  // leads to "sent less money" → wallet credit → no product delivered. Then the confirmed
  // event (with the full amount) is rejected as duplicate.
  if (event === 'payment.underpaid' || req.body?.status === 'underpaid') {
    const underpaidRef = req.body?.meta_data?.refId
    if (paymentId && underpaidRef && !dynopayPaymentIdToRef.has(paymentId)) {
      dynopayPaymentIdToRef.set(paymentId, underpaidRef)
      log(`[DynoPay] Stored underpaid mapping: ${paymentId} → ${underpaidRef}`)
      setTimeout(() => dynopayPaymentIdToRef.delete(paymentId), 86400000)
    }
    log(`[DynoPay] Skipping underpaid event — waiting for confirmed/settled (payment_id: ${paymentId})`)
    return res.send(html('OK'))
  }

  // Deduplicate by payment_id — DynoPay sends multiple webhooks per payment
  if (paymentId && processedDynopayPayments.has(paymentId)) {
    log(`[DynoPay] Duplicate webhook ignored for payment_id: ${paymentId}`)
    return res.send(html('OK'))
  }

  // ── Extract refId — try meta_data first, then fall back to stored mapping from pending event ──
  const { meta_data } = req.body
  let ref = meta_data?.refId
  
  if (!ref && paymentId) {
    ref = dynopayPaymentIdToRef.get(paymentId)
    if (ref) {
      log(`[DynoPay] Recovered refId from pending mapping: payment_id ${paymentId} → refId ${ref}`)
    }
  }
  
  log('Extracted refId:', ref)
  
  const pay = await get(chatIdOfDynopayPayment, ref)
  log('Payment data found for ref:', ref, '=', pay ? 'YES' : 'NO')
  
  if (!pay) {
    log(`[DynoPay] ⚠️ Payment session not found for ref: ${ref}, payment_id: ${paymentId} (event: ${event})`)
    // Alert admin about missed payment
    if (event === 'payment.confirmed' && bot && process.env.TELEGRAM_ADMIN_CHAT_ID) {
      const amount = req.body?.base_amount || req.body?.amount || '?'
      bot.sendMessage(process.env.TELEGRAM_ADMIN_CHAT_ID, 
        `⚠️ <b>Missed Payment Alert</b>\n\n💰 Confirmed payment of <b>$${amount}</b> could not be credited!\n🆔 payment_id: <code>${paymentId}</code>\n📝 refId: <code>${ref || 'missing'}</code>\n\nManual credit may be required.`, 
        { parse_mode: 'HTML' }
      ).catch(() => {})
    }
    return res.send(html('OK'))
  }

  // Mark as processed to block future duplicates
  if (paymentId) {
    processedDynopayPayments.add(paymentId)
    // Auto-cleanup after 1 hour to prevent memory leak
    setTimeout(() => processedDynopayPayments.delete(paymentId), 3600000)
    // Clean up the pending mapping as well
    dynopayPaymentIdToRef.delete(paymentId)
  }
  
  log('Payment session authenticated successfully:', pay)
  req.pay = { ...pay, ref }
  next()
}

