// ── EV IP Failover Notification Endpoint ──
app.post('/ev-ip-failover', (req, res) => {
  try {
    const payload = req.body
    if (!payload || payload.event !== 'ip_failover') return res.status(400).json({ error: 'Invalid payload' })

    const ADMIN_ID = process.env.TELEGRAM_ADMIN_CHAT_ID
    if (ADMIN_ID && bot) {
      const healthy = payload.healthyIps || []
      const msg = `⚠️ <b>EV IP Failover Alert</b>\n\n` +
        `🔴 Blocked: <code>${payload.blockedIp}</code>\n` +
        `📊 Failures: ${payload.failures}\n` +
        `💬 Reason: ${payload.reason}\n\n` +
        `🟢 Healthy IPs: ${healthy.length > 0 ? healthy.map(ip => `<code>${ip}</code>`).join(', ') : '⚠️ NONE — all IPs blocked!'}\n\n` +
        `${healthy.length === 0 ? '🚨 <b>CRITICAL: No healthy IPs! Email validation will fail. Add a new IP immediately.</b>' : `✅ Auto-switched to next healthy IP.`}\n\n` +
        `🕐 ${new Date(payload.timestamp).toLocaleString()}`
      bot.sendMessage(ADMIN_ID, msg, { parse_mode: 'HTML' }).catch(() => {})
    }

    res.json({ ok: true })
  } catch (e) {
    log(`[EV-IP-Failover] Error: ${e.message}`)
    res.status(500).json({ error: 'Internal server error' })
  }
})

app.post('/webhook', auth, (req, res) => {
  log('[Fincra Webhook] Received — endpoint:', req?.pay?.endpoint, 'ref:', req?.pay?.ref)
  const value = req?.body?.data?.amountReceived
  const coin = req?.body?.data?.currency
  const endpoint = req?.pay?.endpoint
  const ref = req?.pay?.ref

  // Reject invalid currency, non-numeric amount, or unknown endpoint
  if (coin !== 'NGN' || isNaN(value) || !bankApis[endpoint]) {
    log(`[Fincra Webhook] ⚠️ Rejected — coin: ${coin}, value: ${value}, endpoint: ${endpoint}`)
    return res.send(html(translation('t.argsErr')))
  }

  // Reject zero or negative amounts — Fincra fires webhooks with amountReceived=0
  // when checkout is created but user never actually sends money
  if (Number(value) <= 0) {
    log(`[Fincra Webhook] ⚠️ Rejected zero/negative amount — ref: ${ref}, value: ₦${value}, endpoint: ${endpoint}`)
    return res.send(html('OK'))
  }

  // Deduplicate — Fincra sometimes sends the same webhook multiple times
  if (ref && processedFincraRefs.has(ref)) {
    log(`[Fincra Webhook] ⚠️ Duplicate ignored — ref: ${ref} already processed`)
    return res.send(html('OK'))
  }
  if (ref) {
    processedFincraRefs.add(ref)
    // Auto-cleanup after 1 hour to prevent unbounded memory growth
    setTimeout(() => processedFincraRefs.delete(ref), 3600000)
  }

  log(`[Fincra Webhook] ✅ Processing: ${endpoint} for ₦${value}`)
  bankApis[endpoint](req, res, Number(value))
})

app.get('/open-api-key', async (req, res) => {
  // Require auth header to prevent unauthorized access
  const authHeader = req.headers['x-api-auth'] || req.query?.auth
  const expectedAuth = process.env.APP_OPEN_API_AUTH || process.env.TELEGRAM_BOT_TOKEN
  if (!authHeader || authHeader !== expectedAuth) {
    return res.status(401).json({ error: 'Unauthorized' })
  }

  const openApiKey = process.env.APP_OPEN_API_KEY
  const length = Math.ceil(openApiKey.length / 3)
  const piece1 = openApiKey.substring(0, length)
  const piece2 = openApiKey.substring(length, length * 2)
  const piece3 = openApiKey.substring(length * 2)

  const responseJson = {
    piece1: piece1,
    piece2: piece3,
    piece3: piece2,
  }

  res.json(responseJson)
})

