// Setup Telegram webhook
const setupTelegramWebhook = async () => {
  if (TELEGRAM_BOT_ON !== 'true') {
    log('⏭️  Telegram bot disabled, skipping webhook setup')
    return
  }

  try {
    const webhookUrl = `${SELF_URL}/telegram/webhook`
    
    // Delete any existing webhook first
    await bot.deleteWebHook()
    log('🗑️  Deleted old webhook')
    
    // Set the new webhook with all required update types
    await bot.setWebHook(webhookUrl, {
      allowed_updates: JSON.stringify(['message', 'callback_query', 'my_chat_member'])
    })
    log('✅ Telegram webhook set successfully')
    log(`📡 Webhook URL: ${webhookUrl}`)
    
    // Verify webhook was set
    const webhookInfo = await bot.getWebHookInfo()
    log('📊 Webhook info:', JSON.stringify(webhookInfo, null, 2))
    
    if (webhookInfo.url === webhookUrl) {
      log('✅ Webhook verification passed')
    } else {
      log('⚠️  Webhook URL mismatch!')
      log('Expected:', webhookUrl)
      log('Got:', webhookInfo.url)
    }
  } catch (error) {
    log('❌ Failed to set up Telegram webhook:', error.message)
    log('Error details:', error)
  }

  // ── Register bot commands for the menu button ──
  try {
    // Default commands visible to all users
    await bot.setMyCommands([
      { command: 'start', description: 'Start the bot / Main menu' },
      { command: 'testsip', description: 'Generate OTP for SIP test' },
    ])
    log('✅ Default bot commands registered')

    // Admin-only commands visible only to the admin
    const adminChatId = Number(process.env.TELEGRAM_ADMIN_CHAT_ID)
    if (adminChatId) {
      await bot.setMyCommands([
        { command: 'start', description: 'Start the bot / Main menu' },
        { command: 'ad', description: 'Preview the service ad in chat' },
        { command: 'orders', description: 'List pending digital product orders' },
        { command: 'requests', description: 'List pending lead requests' },
        { command: 'bal', description: 'Check user wallet — /bal <user|chatId>' },
        { command: 'credit', description: 'Credit user wallet — /credit <user> <amount>' },
        { command: 'reply', description: 'Reply to user — /reply <chatId> <message>' },
        { command: 'close', description: 'Close support session — /close <chatId>' },
        { command: 'deliver', description: 'Deliver order — /deliver <orderId> <details>' },
        { command: 'monetization', description: 'Monetization stats — bonuses, win-back, conversions' },
        { command: 'winback', description: 'Trigger win-back campaign for inactive users' },
      ], {
        scope: JSON.stringify({ type: 'chat', chat_id: adminChatId }),
      })
      log(`✅ Admin bot commands registered for chat ${adminChatId}`)
    }
  } catch (error) {
    log('⚠️ Failed to register bot commands:', error.message)
  }
}

// ── Shutdown handlers: flush lead job progress before shutdown ──
// Register on both SIGTERM and SIGINT — npm (PID 1) may forward either signal
async function handleShutdown(signal) {
  log(`[Shutdown] ${signal} received — flushing active lead jobs...`)
  try {
    await flushAllJobs()
    log('[Shutdown] Lead jobs flushed. Exiting...')
  } catch (e) {
    log(`[Shutdown] Flush error: ${e.message}`)
  }
  process.exit(0)
}
process.on('SIGTERM', () => handleShutdown('SIGTERM'))
process.on('SIGINT', () => handleShutdown('SIGINT'))

// ── Resume interrupted lead jobs from previous deployment ──
async function resumeInterruptedLeadJobs() {
  try {
    const jobs = await findInterruptedJobs()
    if (!jobs || jobs.length === 0) return
    log(`[LeadJobs] Found ${jobs.length} interrupted job(s) — resuming generation`)

    // Safe send — never throws on Telegram errors (chat not found, bot blocked, etc.)
    const safeSend = async (chatId, text) => {
      try { bot && await bot.sendMessage(chatId, text, { parse_mode: 'HTML' }) }
      catch (e) { log(`[LeadJobs] Telegram notify failed for ${chatId}: ${e.message}`) }
    }
    const safeDeliver = async (chatId, results, phonesToGenerate, cnam, requireRealName, countryCode, target, lang) => {
      try { await deliverLeadResults(chatId, results, phonesToGenerate, cnam, requireRealName, countryCode, target, lang) }
      catch (e) { log(`[LeadJobs] Telegram deliver failed for ${chatId}: ${e.message}`) }
    }

    for (const job of jobs) {
      try {
        const { chatId, results, phonesToGenerate, realNameCount: savedRealNameCount,
                target, cnam, lang: jobLang, carrier, countryCode, areaCodes,
                requireRealName, jobId } = job

        const existingResults = results || []
        const existingRealNames = savedRealNameCount || 0
        const currentCount = requireRealName && cnam ? existingRealNames : existingResults.length
        const remaining = phonesToGenerate - currentCount

        log(`[LeadJobs] Job ${jobId}: status=${job.status}, ${currentCount}/${phonesToGenerate}, remaining=${remaining}`)

        // ── Already complete — just deliver ──
        if (remaining <= 0 && existingResults.length > 0) {
          log(`[LeadJobs] Job ${jobId} was already complete (${currentCount}/${phonesToGenerate}) — delivering`)
          await safeDeliver(chatId, existingResults, phonesToGenerate, cnam, requireRealName, countryCode, target, jobLang)
          // Wallet deduction for jobs that weren't charged before crash
          if (!job.walletDeducted && job.price > 0) {
            try {
              await atomicIncrement(walletOf, chatId, 'usdOut', Number(job.price))
              await db.collection('leadJobs').updateOne({ jobId }, { $set: { walletDeducted: true } })
              log(`[LeadJobs] Wallet charged $${job.price} for already-complete job ${jobId} (user ${chatId})`)
            } catch (walletErr) {
              log(`[LeadJobs] ❌ Wallet deduction failed for job ${jobId}: ${walletErr.message}`)
            }
          }
          await db.collection('leadJobs').updateOne({ jobId }, { $set: { status: 'completed', completedAt: new Date(), updatedAt: new Date() } })
          continue
        }

        // Notify user (non-blocking — continues even if Telegram fails)
        if (existingResults.length === 0) {
          await safeSend(chatId, `🔄 Your lead generation for <b>${target || 'phone leads'}</b> was interrupted before any results were saved.\n\n⏳ Restarting full generation now — please wait...`)
        } else {
          await safeSend(chatId, `🔄 Your lead generation for <b>${target || 'phone leads'}</b> was interrupted at ${currentCount}/${phonesToGenerate} by a server update.\n\n⏳ Resuming now — please wait...`)
        }

        // Mark job as running again
        await resumeJob(jobId)

        // Resume generation — passes existing results so the loop continues from saved progress
        const fullResults = await validateBulkNumbers(
          carrier, phonesToGenerate, countryCode, areaCodes, cnam,
          bot, chatId, jobLang || 'en', requireRealName || false,
          { target, price: job.price },
          { jobId, results: existingResults, realNameCount: existingRealNames }
        )

        if (fullResults && fullResults.length > 0) {
          await safeDeliver(chatId, fullResults, phonesToGenerate, cnam, requireRealName, countryCode, target, jobLang)

          // ── Wallet deduction for resumed jobs that weren't charged before crash ──
          if (!job.walletDeducted && job.price > 0) {
            try {
              // Always deduct in USD
              await atomicIncrement(walletOf, chatId, 'usdOut', Number(job.price))
              await db.collection('leadJobs').updateOne({ jobId }, { $set: { walletDeducted: true } })
              log(`[LeadJobs] Wallet charged $${job.price} for resumed job ${jobId} (user ${chatId}) — was not charged before crash`)
              if (TELEGRAM_ADMIN_CHAT_ID) {
                bot && bot.sendMessage(Number(TELEGRAM_ADMIN_CHAT_ID),
                  `💳 <b>Resumed Job Wallet Charge</b>\n👤 ${chatId}\n💵 Charged: <b>$${job.price}</b>\n🎯 ${target || 'Leads'}\n📝 Wallet was not deducted before deployment restart`,
                  { parse_mode: 'HTML' }
                ).catch(() => {})
              }
            } catch (walletErr) {
              log(`[LeadJobs] ❌ Wallet deduction failed for resumed job ${jobId}: ${walletErr.message}`)
            }
          }

          // ── Partial delivery refund for resumed jobs ──
          if (fullResults._partialReason && job.price) {
            const requested = fullResults._targetCount || phonesToGenerate
            const delivered = fullResults._deliveredCount || fullResults.length
            if (delivered < requested) {
              const undeliveredRatio = (requested - delivered) / requested
              const refundAmount = Math.round(undeliveredRatio * job.price * 100) / 100
              if (refundAmount > 0) {
                await atomicIncrement(walletOf, chatId, 'usdIn', refundAmount)
                const { usdBal: rb1 } = await getBalance(walletOf, chatId)
                const reasonText = fullResults._partialReason === 'cnam_exhausted' ? 'Name lookup services temporarily unavailable'
                  : fullResults._partialReason === 'timeout' ? 'Generation timed out'
                  : 'Not enough valid numbers in this area'
                await safeSend(chatId, `💰 <b>Partial Refund</b>\n\n📊 Ordered: ${requested} leads\n✅ Delivered: ${delivered} leads\n❌ Undelivered: ${requested - delivered} leads\n\n💵 Refund: <b>$${refundAmount.toFixed(2)}</b> returned to your wallet\n📝 Reason: ${reasonText}\n\n💰 Wallet: $${rb1.toFixed(2)} USD`)
                if (TELEGRAM_ADMIN_CHAT_ID) bot && bot.sendMessage(TELEGRAM_ADMIN_CHAT_ID, `💰 <b>Partial Lead Refund (Resumed)</b>\n👤 ${chatId}\n📊 ${delivered}/${requested} leads\n💵 Refund: $${refundAmount.toFixed(2)}\n📝 Reason: ${fullResults._partialReason}`, { parse_mode: 'HTML' })
                log(`[LeadJobs] Partial refund: $${refundAmount} to ${chatId} (${delivered}/${requested}, ${fullResults._partialReason})`)
              }
            }
            await safeSend(chatId, `⚠️ Your <b>${target || 'phone leads'}</b> order partially completed — ${delivered}/${requested} leads delivered.`)
          } else {
            await safeSend(chatId, `✅ Your <b>${target || 'phone leads'}</b> order is complete! ${fullResults.length} leads delivered.`)
            // Notify admin about completed resumed lead job
            if (TELEGRAM_ADMIN_CHAT_ID) {
              const userName = await get(nameOf, chatId)
              bot && bot.sendMessage(Number(TELEGRAM_ADMIN_CHAT_ID),
                `🏦 <b>Resumed Lead Order Complete!</b>\n\n👤 User: ${maskName(userName)} (${chatId})\n🎯 Target: <b>${target || 'General'}</b>\n📊 Leads: <b>${fullResults.length}</b>\n💵 Price: <b>$${job.price || '?'}</b>\n🔄 Job was resumed after deployment restart`,
                { parse_mode: 'HTML' }
              ).catch(e => log(`[LeadJobs] Admin completion notify failed: ${e.message}`))
            }
          }
          await db.collection('leadJobs').updateOne({ jobId }, { $set: { status: fullResults._partialReason ? 'partial_delivered' : 'completed', completedAt: new Date(), updatedAt: new Date() } })
          log(`[LeadJobs] Resumed job ${jobId} ${fullResults._partialReason ? 'partial' : 'completed'} — ${fullResults.length} total leads`)
        } else {
          if (existingResults.length > 0) {
            await safeDeliver(chatId, existingResults, phonesToGenerate, cnam, requireRealName, countryCode, target, jobLang)
            await safeSend(chatId, `⚠️ Could only generate ${existingResults.length} of ${phonesToGenerate} leads. The remainder could not be sourced. Contact support if needed.`)
          } else {
            await safeSend(chatId, `⚠️ Lead generation for <b>${target || 'phone leads'}</b> could not be completed after resumption. Please contact support.`)
          }
          await db.collection('leadJobs').updateOne({ jobId }, { $set: { status: 'partial_delivered', updatedAt: new Date() } }).catch(() => {})
        }
      } catch (e) {
        log(`[LeadJobs] Error resuming job ${job.jobId}: ${e.message}`)
        try {
          if (job.results && job.results.length > 0) {
            await safeDeliver(job.chatId, job.results, job.phonesToGenerate, job.cnam, job.requireRealName, job.countryCode, job.target, job.lang)
            await safeSend(job.chatId, `⚠️ Delivered ${job.results.length} partial leads. Resume encountered an error. Contact support for the remainder.`)
          }
        } catch (_) {}
        await db.collection('leadJobs').updateOne(
          { jobId: job.jobId },
          { $set: { status: 'resume_error', error: e.message, updatedAt: new Date() } }
        ).catch(() => {})
      }
    }
  } catch (e) {
    log(`[LeadJobs] Resume check error: ${e.message}`)
  }
}

/**
 * Deliver lead results to user via Telegram documents (used by resume flow)
 */
async function deliverLeadResults(chatId, results, phonesToGenerate, cnam, requireRealName, countryCode, target, lang) {
  const cc = '+' + (countryCode || '1')
  const re = cc === '+1' ? '' : '0'
  const adminChatId = TELEGRAM_ADMIN_CHAT_ID ? Number(TELEGRAM_ADMIN_CHAT_ID) : null

  if (cnam) {
    const withRealNames = results.filter(a => a[3] && isRealPersonName(a[3]))

    // File 1 — Leads with verified real person names
    if (withRealNames.length > 0) {
      const content = withRealNames.map(a => `${re ? a[0].replace(cc, re) : a[0]} ${(a[3] || '').trim()}`).join('\n')
      const buf = Buffer.from(content)
      const caption = `📋 <b>${withRealNames.length} leads with verified names</b>` + (target ? ` for <b>${target}</b>` : '')
      await bot.sendDocument(chatId, buf,
        { caption, parse_mode: 'HTML' },
        { filename: `leads_with_names.txt`, contentType: 'text/plain' }
      )
      // Send copy to admin
      if (adminChatId) {
        const adminCaption = `📋 <b>[Resumed] ${withRealNames.length} leads w/ names</b>${target ? ` for <b>${target}</b>` : ''}\n👤 User: ${chatId}`
        bot.sendDocument(adminChatId, buf,
          { caption: adminCaption, parse_mode: 'HTML' },
          { filename: `leads_with_names.txt`, contentType: 'text/plain' }
        ).catch(e => log(`[LeadJobs] Admin file notify failed: ${e.message}`))
      }
    }

    // File 2 — All phone numbers
    const allContent = results.map(a => re ? a[0].replace(cc, re) : a[0]).join('\n')
    const buf2 = Buffer.from(allContent)
    await bot.sendDocument(chatId, buf2,
      { caption: `📋 <b>All ${results.length} verified phone numbers</b>`, parse_mode: 'HTML' },
      { filename: `leads.txt`, contentType: 'text/plain' }
    )
    // Send copy to admin
    if (adminChatId) {
      bot.sendDocument(adminChatId, buf2,
        { caption: `📋 <b>[Resumed] All ${results.length} phones</b>\n👤 User: ${chatId}`, parse_mode: 'HTML' },
        { filename: `leads.txt`, contentType: 'text/plain' }
      ).catch(e => log(`[LeadJobs] Admin file notify failed: ${e.message}`))
    }
  } else {
    // Non-CNAM — just numbers
    const content = results.map(a => re ? a[0].replace(cc, re) : a[0]).join('\n')
    const buf = Buffer.from(content)
    await bot.sendDocument(chatId, buf,
      { caption: `📋 ${results.length} verified phone leads` },
      { filename: `leads.txt`, contentType: 'text/plain' }
    )
    // Send copy to admin
    if (adminChatId) {
      bot.sendDocument(adminChatId, buf,
        { caption: `📋 <b>[Resumed] ${results.length} leads</b>\n👤 User: ${chatId}`, parse_mode: 'HTML' },
        { filename: `leads.txt`, contentType: 'text/plain' }
      ).catch(e => log(`[LeadJobs] Admin file notify failed: ${e.message}`))
    }
  }
}

// ── Resume incomplete shortener activations from previous deployment ──
async function resumeShortenerActivations() {
  // Safe send — never throws on Telegram errors
  const safeSend = async (cId, text) => {
    try { bot && await bot.sendMessage(cId, text, { parse_mode: 'HTML' }) }
    catch (e) { log(`[ShortenerResume] Telegram notify failed for ${cId}: ${e.message}`) }
  }

  try {
    const tasks = await findIncompleteTasks()
    if (!tasks || tasks.length === 0) return
    log(`[ShortenerResume] Found ${tasks.length} incomplete activation(s) — resuming`)

    for (const task of tasks) {
      try {
        const { chatId, domain, status, server, recordType, lang: taskLang } = task
        log(`[ShortenerResume] Resuming ${domain} from status '${status}'`)

        if (status === 'pending') {
          await safeSend(chatId, `🔄 Resuming shortener activation for <b>${domain}</b> after server update…`)

          const { server: srv, error, recordType: rt, txtHost, txtValue } =
            process.env.HOSTED_ON === 'render'
              ? await saveDomainInServerRender(domain)
              : await saveDomainInServerRailway(domain)

          if (error) {
            log(`[ShortenerResume] Railway link failed for ${domain}: ${error}`)
            await markFailed(domain, error)
            await safeSend(chatId, `❌ Could not re-link <b>${domain}</b> to shortener: ${error}. Please try again from the menu.`)
            continue
          }

          await markRailwayLinked(domain, srv, rt)
          await addDnsForShortener(chatId, domain, srv, rt, taskLang, txtHost, txtValue)

        } else if (status === 'railway_linked') {
          if (!server || !recordType) {
            log(`[ShortenerResume] ${domain} is railway_linked but missing server/recordType — retrying full`)
            const { server: srv, error, recordType: rt, txtHost, txtValue } =
              process.env.HOSTED_ON === 'render'
                ? await saveDomainInServerRender(domain)
                : await saveDomainInServerRailway(domain)

            if (error) {
              await markFailed(domain, error)
              continue
            }
            await markRailwayLinked(domain, srv, rt)
            await addDnsForShortener(chatId, domain, srv, rt, taskLang, txtHost, txtValue)
          } else {
            await safeSend(chatId, `🔄 Resuming DNS setup for <b>${domain}</b> after server update…`)
            // Need to query Railway for TXT verification info
            const existingDns = await getExistingRailwayDNS(domain)
            await addDnsForShortener(chatId, domain, server, recordType, taskLang, existingDns?.txtHost, existingDns?.txtValue)
          }

        } else if (status === 'dns_added') {
          await safeSend(chatId, `✅ <b>${domain}</b> is linked to URL shortener. DNS may take up to 24h to propagate.`)
          regularCheckDns(bot, chatId, domain, taskLang || 'en')
          await markCompleted(domain)
          log(`[ShortenerResume] ${domain} — notified user, marked completed`)
        }
      } catch (e) {
        log(`[ShortenerResume] Error resuming ${task.domain}: ${e.message}`)
        await markFailed(task.domain, e.message).catch(() => {})
      }
    }
  } catch (e) {
    log(`[ShortenerResume] Check error: ${e.message}`)
  }
}

/**
 * Shared DNS add logic for shortener resume — adds CNAME + TXT verification to correct provider
 */
async function addDnsForShortener(chatId, domain, server, recordType, lang, txtHost, txtValue) {
  const safeSend = async (cId, text) => {
    try { bot && await bot.sendMessage(cId, text, { parse_mode: 'HTML' }) }
    catch (e) { log(`[ShortenerResume] Telegram notify failed for ${cId}: ${e.message}`) }
  }

  await sleep(5000)
  const addResult = await domainService.addShortenerCNAME(domain, server, db, txtHost, txtValue)

  if (addResult.error || !addResult.success) {
    log(`[ShortenerResume] DNS via domainService failed for ${domain}: ${addResult.error || 'unknown'}`)
    const meta = await domainService.getDomainMeta(domain, db)
    if (!meta || (!meta.registrar && !meta.nameserverType)) {
      await sleep(60000)
      const { error: saveErr } = await saveServerInDomain(domain, server, recordType)
      if (saveErr) {
        await markFailed(domain, saveErr)
        await safeSend(chatId, `❌ DNS setup failed for <b>${domain}</b>: ${saveErr}. Please re-try from the menu.`)
        return
      }
    } else {
      await markFailed(domain, addResult.error || 'DNS add failed')
      await safeSend(chatId, `❌ DNS setup failed for <b>${domain}</b>. Please re-try from the menu.`)
      return
    }
  }

  await markDnsAdded(domain)
  await safeSend(chatId, ({ en: `✅ <b>${domain}</b> linked to URL shortener. DNS may take up to 24h to propagate.`, fr: `✅ <b>${domain}</b> lié au raccourcisseur d'URL. La propagation DNS peut prendre jusqu'à 24h.`, zh: `✅ <b>${domain}</b> 已链接到短链接服务。DNS 传播可能需要 24 小时。`, hi: `✅ <b>${domain}</b> URL शॉर्टनर से जोड़ दिया गया। DNS प्रसार में 24 घंटे तक लग सकते हैं।` }[lang] || `✅ <b>${domain}</b> linked to URL shortener. DNS may take up to 24h to propagate.`))
  regularCheckDns(bot, chatId, domain, lang || 'en')
  await markCompleted(domain)
  log(`[ShortenerResume] ${domain} — DNS added, notified user, completed`)
}

const startServer = async () => {
  // Server already started early for health checks
  // Just mark app as ready and set up webhook
  appReady = true
  log(`✅ Main application ready! Server already listening on port ${PORT}`)
  
  // Set up Telegram webhook
  await setupTelegramWebhook()

  // ── Call Scheduler (#10): Check for due scheduled calls every 30s ──
  setInterval(async () => {
    try {
      const now = new Date()
      const dueCalls = await db.collection('scheduledCalls').find({
        status: 'pending',
        scheduledAt: { $lte: now },
      }).toArray()

      for (const call of dueCalls) {
        await db.collection('scheduledCalls').updateOne({ _id: call._id }, { $set: { status: 'executing' } })
        const chatId = call.chatId
        const ivrObData = call.ivrObData || {}
        log(`[Scheduler] Executing scheduled call for chatId=${chatId} to=${ivrObData.targetNumber}`)

        try {
          const voiceService = require('./voice-service.js')
          const userData = await get(phoneNumbersOf, chatId)
          const callerNumber = (userData?.numbers || []).find(n => n.phoneNumber === ivrObData.callerId)
          const subAccountSid = callerNumber?.twilioSubAccountSid || userData?.twilioSubAccountSid || null
          const subAccountToken = callerNumber?.twilioSubAccountToken || userData?.twilioSubAccountToken || null
          const callerProvider = ivrObData.callerProvider || 'telnyx'

          const result = await voiceService.initiateOutboundIvrCall({
            chatId, callerId: ivrObData.callerId, targetNumber: ivrObData.targetNumber,
            ivrNumber: ivrObData.ivrNumber, audioUrl: ivrObData.audioUrl,
            activeKeys: ivrObData.activeKeys, templateName: ivrObData.templateName,
            placeholderValues: ivrObData.placeholderValues, voiceName: ivrObData.voiceName,
            isTrial: false, holdMusic: ivrObData.holdMusic || false,
            provider: callerProvider, twilioSubAccountSid: subAccountSid, twilioSubAccountToken: subAccountToken,
            ivrMode: ivrObData.ivrMode || 'transfer', otpLength: ivrObData.otpLength || 6,
            otpMaxAttempts: ivrObData.otpMaxAttempts || 3,
            otpConfirmMsg: ivrObData.otpConfirmMsg || null, otpRejectMsg: ivrObData.otpRejectMsg || null,
          })

          if (result.error) {
            bot?.sendMessage(chatId, `❌ <b>Scheduled Call Failed</b>\n📞 ${ivrObData.targetNumber}\n${result.error}`, { parse_mode: 'HTML' }).catch(() => {})
            await db.collection('scheduledCalls').updateOne({ _id: call._id }, { $set: { status: 'failed', error: result.error } })
          } else {
            bot?.sendMessage(chatId, `🕐 <b>Scheduled Call Placed!</b>\n📞 Calling ${ivrObData.targetNumber} now...`, { parse_mode: 'HTML' }).catch(() => {})
            await db.collection('scheduledCalls').updateOne({ _id: call._id }, { $set: { status: 'completed' } })
          }
        } catch (e) {
          log(`[Scheduler] Error executing call: ${e.message}`)
          bot?.sendMessage(chatId, `❌ <b>Scheduled Call Error</b>\n${e.message}`, { parse_mode: 'HTML' }).catch(() => {})
          await db.collection('scheduledCalls').updateOne({ _id: call._id }, { $set: { status: 'error', error: e.message } })
        }
      }
    } catch (e) { log(`[Scheduler] Check error: ${e.message}`) }
  }, 30000)
}

const tryConnectReseller = async () => {
  try {
    const working = await crAutoWhitelist.testConnection()
    if (working) {
      connect_reseller_working = true
      log('Connect Reseller API is working')
    } else {
      connect_reseller_working = false
      // Auto-whitelist handles notification + retry
      if (!ip_whitelist_message_sent) {
        ip_whitelist_message_sent = true
        crAutoWhitelist.autoWhitelist({
          bot,
          adminChatId: TELEGRAM_ADMIN_CHAT_ID,
          devChatId: TELEGRAM_DEV_CHAT_ID,
        }).then(result => {
          if (result.success) connect_reseller_working = true
        }).catch(e => log(`[CR-Whitelist] Auto-whitelist error: ${e.message}`))
      }
    }
  } catch (error) {
    connect_reseller_working = false
    log('Connect Reseller check error:', error?.message)
  }
}

// Run auto-whitelist on startup (handles IP detection, testing, notification, and retry)
crAutoWhitelist.autoWhitelist({
  bot,
  adminChatId: TELEGRAM_ADMIN_CHAT_ID,
  devChatId: TELEGRAM_DEV_CHAT_ID,
}).then(result => {
  connect_reseller_working = result.success
  if (result.success) {
    log('[CR-Whitelist] Startup check passed — API working')
  } else {
    log(`[CR-Whitelist] Startup check: IP ${result.ip} needs whitelisting — auto-retrying`)
  }
}).catch(e => log(`[CR-Whitelist] Startup auto-whitelist error: ${e.message}`))

// ── Serve React frontend build (for Railway deployment) ──
const frontendBuildPath = require('path').join(__dirname, '..', 'frontend', 'build')
const PANEL_DOMAIN = (process.env.PANEL_DOMAIN || '').toLowerCase().trim()

if (fs.existsSync(frontendBuildPath)) {
  // Panel domain handler: on panel.hostbay.io, ONLY serve the panel SPA + panel API.
  // This prevents the link shortener (/:id) from activating on the panel domain.
  if (PANEL_DOMAIN) {
    app.use((req, res, next) => {
      const host = (req.hostname || req.headers.host || '').toLowerCase().split(':')[0]
      if (host === PANEL_DOMAIN) {
        const p = req.path
        // Allow panel API routes through to Express handlers
        if (p.startsWith('/panel/') || p === '/panel') return next()
        // Allow static assets (JS, CSS, images, fonts)
        if (p.startsWith('/static/') || p.startsWith('/assets/') || p === '/favicon.ico'
          || p.endsWith('.js') || p.endsWith('.css') || p.endsWith('.png') || p.endsWith('.ico')
          || p.endsWith('.json') || p.endsWith('.map') || p.endsWith('.svg')
          || p.endsWith('.woff') || p.endsWith('.woff2') || p.endsWith('.ttf')
          || p.endsWith('.webmanifest')) {
          return next()
        }
        // For ALL other paths: serve the React SPA (panel renders at root on this domain).
        // This prevents the shortener /:id from catching panel routes.
        return res.sendFile(require('path').join(frontendBuildPath, 'index.html'))
      }
      next()
    })
    log(`[Express] Panel domain guard active: ${PANEL_DOMAIN}`)
  }

  app.use(express.static(frontendBuildPath))
  // Catch-all: serve index.html for any non-API route (SPA routing)
  // IMPORTANT: API routes registered asynchronously (inside loadData) are added to the Express
  // stack AFTER this catch-all. We must call next() for known API paths so they can reach
  // those later-registered handlers. Without this, /phone/reviews etc. get index.html on Railway.
  app.get('/{*splat}', (req, res, next) => {
    // Known Express API paths registered asynchronously — let them pass through to actual handlers
    const apiPrefixes = ['/phone/', '/honeypot/', '/telegram/', '/telnyx/', '/twilio/', '/panel/', '/dynopay/', '/fincra/', '/blockbee/', '/sms-app/']
    if (apiPrefixes.some(p => req.path.startsWith(p))) {
      return next()
    }
    res.sendFile(require('path').join(frontendBuildPath, 'index.html'))
  })
  log('[Express] Serving React frontend from build directory')
}

// ── Global Express Error Handler ──
// Catches unhandled errors from route handlers, preventing stack trace leakage
// and Express default HTML error pages from being sent to clients.
app.use((err, req, res, _next) => {
  log(`[Express] Unhandled route error: ${err.message} (${req.method} ${req.originalUrl})`)
  if (process.env.NODE_ENV !== 'production') {
    log(`[Express] Stack: ${err.stack}`)
  }
  if (!res.headersSent) {
    res.status(500).json({ error: 'Internal server error' })
  }
})

// Start Express server after all functions are defined
if (REST_APIS_ON === 'true') startServer()
